var profiles = [
    {"profileId": "aarav-garai", "id": "aarav-garai", "name": "Aarav Garai", "imgurl": "AaravGarai.jpg", "description": "Hey, my name is Aarav Garai. I am currently a senior at Bellarmine College Preparatory located in San Jose. A large part of my academics has revolved around the field of math. Some of my achievements in math include finishing 1st nationally in 4th grade for Math Kangaroo and qualifying for AMC 10 two times and receiving an Honor Roll. An interesting fact about myself, outside of academics, is that I have been playing soccer for the last 10 years. Overall, I look forward to teaching students at Silicon Valley Youth about the AMC 8 Basic."},
    {"profileId": "aaron-peng", "id": "aaron-peng", "name": "Aaron Peng", "imgurl": "AaronPeng.jpg", "description": "Hi everyone! My name is Aaron Peng and I am a junior at Mountain View High School. This is my fourth semester teaching at SVY and I will be one of your teachers. I have placed within the top 20% of the USABO and taken Honors Biology. I’m super excited to meet all of you, and will do my best to teach you all what I know!"},
    {"profileId": "aiden-lin", "id": "aiden-lin", "name": "Aiden Lin", "imgurl": "AidenLin.jpg", "description": "Aiden is currently a sophomore at Palo Alto High School and this is his third semester at SVY. He is proficient in Python and Java, has scored a 5 on the AP CS A exam, and is currently in the silver division of USACO. His hobbies include programming, cartography, and basketball."},
    {"profileId": "aiden-ye", "id": "aiden-ye", "name": "Aiden Ye", "imgurl": "AidenYe.jpg", "description": "Aiden Ye is a 12th grader at Saratoga High School and has been teaching Science Bowl for the past five years. He founded Redwood Middle School’s science bowl club. He is passionate about science and math, and has qualified for AIME every year since 8th grade as well as reaching USAPHO Bronze. Aiden is excited to be teaching Science Bowl at Silicon Valley Youth and meeting new students."},
    {"profileId": "akhil-aggarwal", "id": "akhil-aggarwal", "name": "Akhil Aggarwal", "imgurl": "AkhilAggarwal.jpg"},
    {"profileId": "alan-yue", "id": "alan-yue", "name": "Alan Yue", "imgurl": "AlanYue.jpg", "description": "Alan Yue is a Senior at Gunn High School. A California Arts Scholar, National Student Poet Semifinalist, and Kenyon Review Young Writers Workshop participant, Alan will be attending Columbia University this fall. He writes poetry and short stories, with the occasional screenplay. Other than writing, Alan is very passionate about jazz music and plays saxophone."},
    {"profileId": "alex-lee", "id": "alex-lee", "name": "Alex Lee", "imgurl": "AlexLee.jpg"},
    {"profileId": "alex-niu", "id": "alex-niu", "name": "Alex Niu", "imgurl": "AlexNiu.jpg"},
    {"profileId": "alex-wang", "id": "alex-wang", "name": "Alex Wang", "imgurl": "AlexWang.jpg", "description": "Alex is a senior at Saratoga High School. He has extensive experience in math competitions, scoring high on both the AMC 8 and AMC 12 and qualifying for AIME five times. He also took Mathcounts and qualified for states as an eighth-grader. He has experience teaching math classes at SVY and his school math club. In his free time, he likes to play basketball and cook. He is excited to work with his students!"},
    {"profileId": "alex-xu", "id": "alex-xu", "name": "Alex Xu", "imgurl": "AlexXu.jpg", "description": "Alex Xu will be a co-teacher for the Public Speaking and Debate course at SVY. He is excited to be able to help teach people essential skills such as public speaking and critical thinking. He has debated Public Forum debate for three years and has recently attended the National Debate Forum's program for PF. His most recent accomplishment is semifinaling at the 2019 Western JV Championships. This is his second time teaching this class and he hopes that this semester will be a fun and engaging experience for both him and the students."},
    {"profileId": "alex-yun", "id": "alex-yun", "name": "Alex Yun", "imgurl": "AlexYun.jpg"},
    {"profileId": "alex-zhang", "id": "alex-zhang", "name": "Alex Zhang", "imgurl": "AlexZhang.jpg", "description": "Alex Zhang is a returning TA for the SVY Speech and Debate class, and is excited to teach for his second year. As an 8th grader, he currently attends Kennedy Middle School, and has been doing speech and debate for over 2 years. As a competitor in various middle school and high school competitions, he has done a variety of events including public forum, impromptu, extemporaneous, and duo interpretation. He has previously taught for the Public speaking and Current events class."},
    {"profileId": "alex-zheng", "id": "alex-zheng", "name": "Alex Zheng", "imgurl": "AlexZheng.png", "description": "My name is Alex Zheng, and I am a freshman at Lynbrook High School. I will be TAing for Chess in the spring. I really enjoy playing chess and I have had a lot of experience working with students of varying ages. At a young age, I became interested in chess and soon it became one of the most important things in my life. I also enjoy playing music, which also takes up a large chunk of my time. In my free time, I enjoy taking walks and reading. I look forward to making the class as fun and interesting as possible!"},
    {"profileId": "alison-yang", "id": "alison-yang", "name": "Alison Yang", "imgurl": "AlisonYang.jpg", "description": "Hi! I'm a senior at Harker High School. Any literature has always fascinated me, but I must say that I still have a soft spot for good fiction. Before starting Book Club several semesters ago, I was TA for Intro to Public Speaking and taught English for a summer in China. An alumna of the Iowa Young Writers’ Studio and the Kenyon Review Young Writers’ Workshop, I also serve as the editor-in-chief for my school's newspaper. I've also been recognized by the Alliance for Young Writers and the Santa Clara County Youth Poet Laureate. I am currently wrangling her cat and playing fishing simulators. Looking forward to reading together!"},
    {"profileId": "allen-chang", "id": "allen-chang", "name": "Allen Chang", "imgurl": "AllenChang.jpg"},
    {"profileId": "allison-chang", "id": "allison-chang", "name": "Allison Chang", "imgurl": "AllisonChang.jpg", "description": "Allison Chang is a junior at Palo Alto Senior High School who is passionate about the interdisciplinary chemical sciences. Having been both an astrochemistry intern and a biochemistry intern at UCSC, she has experience working in different sectors in chemistry. When not in the lab, you can find Allison baking or attending an escape room!"},
    {"profileId": "alvin-tian", "id": "alvin-tian", "name": "Alvin Tian", "imgurl": "AlvinTian.jpg", "description": "Hey guys! I’m Alvin Tian, a sophomore at Monta Vista High School. I’ve been doing math my whole life, starting when I was three. I’ve done so many math competitions it’s hard to count them all. I’ve done Mathleague, Mathcounts, AMC8, AMC10, etc… In my spare time, I enjoy exercising and reading. I’m looking forward to teaching this class, and I hope that I’ll see you there!"},
    {"profileId": "ambrose-wang", "id": "ambrose-wang", "name": "Ambrose Wang", "imgurl": "AmbroseWang.jpg", "description": "I'm Ambrose Wang a freshman at Saratoga High School. I am the CAD lead of my robotics team Levithan Robotics and helped win our team the Design award. In my two years of robotics, I've made regionals twice and division finalists once. Outside of CAD, I enjoy doing competive archery."},
    {"profileId": "amelia-yuan", "id": "amelia-yuan", "name": "Amelia Yuan", "imgurl": "AmeliaYuan.jpg", "description": "Hello! My name is Amelia Yuan, and I'm a freshman at Castilleja School. I am going on my fourth year of Model UN and am so excited to be teaching this course. I have been awarded at conferences on a local and national high school level, including NAIMUN at Georgetown. In addition to Model UN, I also have experience in the speech/debate world, and finaled last year at CHSSA in Impromptu speech. In my free time, I enjoy keeping up with current events, reading, and playing water polo."},
    {"profileId": "amruta-dharmapurikar", "id": "amruta-dharmapurikar", "name": "Amruta Dharmapurikar", "imgurl": "AmrutaDharmapurikar.jpg", "description": "Amruta is a sophomore at The Harker School in San Jose, CA. She enjoys participating in math competitions, running, and writing for the school newspaper. She hopes to introduce students to the world of competitive math and help them enjoy it and become successful."},
    {"profileId": "anagha-badriprasad", "id": "anagha-badriprasad", "name": "Anagha Badriprasad", "imgurl": "AnaghaBadriprasad.jpg", "description": "Anagha is a sophomore at Cupertino High. She has conducted innovative bioengineering and computational research at the Synopsys Championship and the California State Science Fair for 4 years, winning prestigious fair and organizational awards. Additionally, her team-created provisional patent for a clean energy solution has won various scholarships and a top award in the global Pete Conrad Challenge. Apart from SVY, Anagha leads student research as an officer for her school’s STEM club and is an active leader at various STEM-affiliated non-profit organizations, including Next Generation Nations. Anagha participates in hackathons, applying her scientific studies to relevant ML software endeavors. In her free time, she plays field hockey and enjoys volunteering. She looks forward to teaching and is excited to help students excel in this course!"},
    {"profileId": "anastasia-miin", "id": "anastasia-miin", "name": "Anastasia Miin", "imgurl": "AnastasiaMiin.jpg", "description": "Hi! I’m Anastasia, an incoming sophomore. I’ve been a singer and pianist for almost 10 years. My love for the performing arts has led me to win many competitions, including NATS SF/Western region, USIMC, and VOCE State. I also qualified for the NATS Nationals vocal competition, was invited for CCDA’s Regional and All-State Honor Choirs, and earned the ARSM piano diploma. Outside of music, I like to go on road trips with my family and play badminton. I'm excited to share my musical passion with peers and to enjoy our students’ compositions!"},
    {"profileId": "andrew-peng", "id": "andrew-peng", "name": "Andrew Peng", "imgurl": "AndrewPeng.jpg", "description": "I am Andrew Peng, a junior at Gunn High School. I am an AIME and USAJMO qualifier, and I have been a math instructor for a few years at Silicon Valley Youth. I have also been actively participating in math competitions since 5th grade, from AMC to MathCounts to HMMT. In my free time, I like to play chess."},
    {"profileId": "andrew-zhao", "id": "andrew-zhao", "name": "Andrew Zhao", "imgurl": "AndrewZhao.jpg", "description": "Andrew Zhao is a senior at Gunn High School. He is experienced in math competitions: he has participated in AMC 8, AMC 10, AMC 12, AIME, HMMT, CHMMC, and ARML When he was on the Mathcounts JLS team, his team won 2nd in the Peninsula Chapter and 4th in Northern California. He is a three time AIME qualifier, and has placed in top 10 in the Caltech-Harvey Mudd Math Tournament; his team also received 4th place at that competition. He has been teaching math at SVY for two years, and is the current Vice President of Math During his free time, he like to program and to go hiking."},
    {"profileId": "andrew-zhou", "id": "andrew-zhou", "name": "Andrew Zhou", "imgurl": "AndrewZhou.jpg"},
    {"profileId": "andy-li", "id": "andy-li", "name": "Andy Li", "imgurl": "AndyLi.jpg", "description": "As a current senior at Lynbrook High School, Andy strives to grow as a student and as a teacher. He has over three years of debating experience, having competed in many public speaking contests before, even earning a Director's Award for Public Forum. While Andy is most familiar with Parliamentary and Public Forum styles of debate, he also understands the other various speech and debate events. Andy now has over four years of teaching experience and is the current SVY Vice President of Public Speaking as well as the ASB Vice President of his school."},
    {"profileId": "andy-xu", "id": "andy-xu", "name": "Andy Xu", "imgurl": "AndyXu.jpg", "description": "Andy is a senior at Lynbrook High School, and this will be his ninth session of teaching at SVY. In his free time, Andy enjoys partaking in debate, FBLA, and volleyball. He has done debate for over four years and has competed at many tournaments such as Stanford Invitational and University of Pacific at Stockton. In tournaments, he has competed in public speaking including various humorous interpretations. In FBLA, Andy was the Miller FBLA president. He has always competed in Public Speaking II and has won 10th and 6th in previous years at the state level. As a sport, he plays club volleyball and play for MVVC 18-Red, which has been consistently a top five seeded team across the entire country. Besides that, Andy plays sports, listens to music, and draws. He enjoys working with kids and hopes to compel younger students to develop the same passions that he has."},
    {"profileId": "angela-li", "id": "angela-li", "name": "Angela Li", "imgurl": "AngelaLi.jpg", "description": "Hi! My name is Angela Li and I am a senior at Basis Independent Silicon Valley. This is my sixth semester teaching at SVY. I have been taking biology courses for 6+ years, and I scored a 5 in AP Biology. I also compete in Science Olympiad life science events and participate in bioinformatics research. I’m excited to share my interest in biology with all of you this semester!"},
    {"profileId": "angela-zhang", "id": "angela-zhang", "name": "Angela Zhang", "imgurl": "AngelaZhang.jpg", "description": "Hi! I'm a sophomore at Saint Francis High School. I've loved reading since forever - whether it's physical books or e-books, I'm all in. I've been student at SVY since fourth grade, and I'm thrilled to now be teaching a class of my own! I took English Honors as a freshman, tutored students in both math and English, and coach basketball outside of school. As a starter on my school's basketball team, I'm excited to bring that same energy and teamwork as we explore some great stories together!"},
    {"profileId": "angelica-wang", "id": "angelica-wang", "name": "Angelica Wang", "imgurl": "AngelicaWang.jpg", "description": "And I’m Angelica! I’m an 8th grader at Kennedy Middle School. I really like life science and how it ties into the medical field. I find molecular/cell biology particularly fascinating. At school, I run cross-country, wrestle, play the bari sax, and run the literature club. Outside of school, I like to read, draw, participate in writing contests, and volunteer my time at the community services center. Also, I am probably not a genetic copy of Cynthia. (We will discuss clones in class.) I am really happy to be teaching bio, and I’m ready to bring an effective learning environment with me. Hope to see you at bio class soon!"},
    {"profileId": "angeline-hu", "id": "angeline-hu", "name": "Angeline Hu", "imgurl": "AngelineHu.jpg", "description": "Hello! I am Angeline Hu, a senior at Gunn High School, and this is my fourth year teaching public speaking and debate at SVY. I’m the captain of the public forum debate team at Gunn, and have been competing on the national circuit going on four years now, during which I’ve competed at 18+ varsity tournaments. Over the past few years, public speaking and debate has given me a tight-knit community, an insurmountable amount of knowledge, and an indispensable skill set that I hope to share with all of you!"},
    {"profileId": "angeline-su", "id": "angeline-su", "name": "Angeline Su", "imgurl": "AngelineSu.jpg", "description": "Hi, I'm Angeline Su, a sophomore, and I'm so excited to be teaching this semester for speech & debate! I have done debate for around 2 years, and compete in LD. I love dancing and painting in my free time."},
    {"profileId": "ankang-hong", "id": "ankang-hong", "name": "Ankang Hong", "imgurl": "AnkangHong.jpg", "description": "Ankang is a junior at Archbishop Mitty High School. He enjoys doing math and has been participating in math competitions since middle school. Some of his achievements include representing his school at the Berkeley Math Tournament and getting an honorable mention in the general round twice and qualifying for the AMC 8 Honor Roll. Besides math, some of his other interests are programming and badminton."},
    {"profileId": "anna-yang", "id": "anna-yang", "name": "Anna Yang", "imgurl": "AnnaYang.jpg", "description": "Anna Yang is a senior at Notre Dame High School and the current Youth Poet Laureate of Santa Clara County. Her journalism, poetry, and short stories appear in the New York Times, DoveTales International Literary Journal of the Arts, the \\\"Reproductive Justice is for Everyone!\\\" Art Exhibition, and more. She has been recognized by the Scholastic Art and Writing Awards, the Poetry Society of the UK, Amanda Gorman Future Voices Poetry Prize, National Council of Teachers of English, and is a graduate of the Iowa Young Writers' Studio. In her free time, she enjoys beekeeping, competing in Model UN, and advocating for social change. Anna is excited to be teaching her 8th semester at SVY!"},
    {"profileId": "annabelle-miin", "id": "annabelle-miin", "name": "Annabelle Miin", "imgurl": "AnnabelleMiin.jpg", "description": "Annabelle Miin is a 17 year old singer and piano player from Saratoga. She began singing and playing piano at age 6. She placed first place in: 2023 VOCE State, 2023 American Protege, 2023 Kings Peak Music Competition, 2021 USIMC, 7th International Music Festival of Melbourne, Spotlight duet competitions and Solo Finalist at Hal Leonard. Beyond competitions, she scored a 5 in AP Music Theory in 9th grade, passed ABRSM piano level 8 in 8th grade, RCM vocal level 8 in 7th grade, and CM vocal levels 9 & 10 with State Honors. She was also named a California Art Scholar, and awarded the Governor’s Medallion. Lastly, she also represented Saratoga High at the California State Honors Choir. During her free time, she enjoys dancing to KPop songs and teaching at Girls Who Code."},
    {"profileId": "annli-zhu", "id": "annli-zhu", "name": "Annli Zhu", "imgurl": "AnnliZhu.jpg", "description": "Annli is a senior at the Nueva School, and this is her seventh semester teaching at SVY (having taught math and Model UN previously). Having piloted programs with Ravenswood Middle School as co-president, she is excited to take advantage of her teaching and Spanish-speaking skills to mentor the Reading Buddies program. At school, Annli is president of the Math and Linguistics Clubs, as well as a member of Nueva’s MUN and varsity basketball team. She is very excited to bring her love of learning to more students in the community this semester."},
    {"profileId": "anouk-yeh", "id": "anouk-yeh", "name": "Anouk Yeh", "imgurl": "AnoukYeh.jpg", "description": "Anouk Yeh is a sophomore at Saratoga High School. She joined speech and debate in sixth grade and has been competing ever since. Throughout her career, she has qualified for and competed at prestigious national tournaments including the NSDA National Speech and Debate Tournament, the CHSSA California State Championships, the University of Kentucky's Tournament of Champions, the National Individual Events Tournament of Champions and the NCFL Grand Nationals. In conjunction with speech and debate, Anouk enjoys utilizing public speaking to inspire social change. She is a 2020 YoungArts winner, and has been invited to speak at various public events including the 2019 National Young Artist’s Summit and the International Congress of Youth Voices. In her free time, Anouk enjoys hanging out with her horse and writing poetry. She is very excited to expose her students to the wonderful world of competitive speech and the power of public speaking."},
    {"profileId": "anping-huang", "id": "anping-huang", "name": "Anping Huang", "imgurl": "AnpingHuang.jpg", "description": "Anping Huang is a sophomore at Lynbrook High School and this is his 2nd year teaching at SVY. He is proficient in programming languages such as Python and Java, and has been coding for the past 4+ years. His passions include programming, video editing, art, and swimming."},
    {"profileId": "anping-zhu", "id": "anping-zhu", "name": "Anping Zhu", "imgurl": "AnpingZhu.jpg", "description": "A junior at the Nueva School, Anping is excited to continue his work in SVY with a new program starting Fall 2022: The Reading Buddies program with the Ravenswood school district. Before this, Anping co-designed and taught a Model United Nations class at SVY. He has won awards in MUN, debate, as well as other history-related writing contests. Anping’s other hobbies include cross-country, track, and reading."},
    {"profileId": "anrui-hong", "id": "anrui-hong", "name": "Anrui Hong", "imgurl": "AnruiHong.jpg", "description": "Anrui is a junior at Archbishop Mitty High School. He has competed in many math competitions since middle school. He has gotten honorable mentions at the Berkeley Math Tournament and Stanford Math Tournament and qualified for the AMC 8 Honor Roll and AIME. He is part of his school’s robotics club and is proficient in Python and C++. In his free time, he likes to play badminton, read, and program."},
    {"profileId": "ansh-chaurasia", "id": "ansh-chaurasia", "name": "Ansh Chaurasia", "imgurl": "AnshChaurasia.jpg", "description": "Ansh Chaurasia is a Junior at Monta Vista High School. He is a gregarious code loving person with programming experience in C++, Java, and web development. His interest in coding led him to qualify for USACO Gold. Besides coding, he enjoys Physics and taken AP Physics in his sophomore years. Ansh has taught SVY classes in the past and is looking forward to spread his passion of Physics. With all of the experience and knowledge, Ansh hopes to make a positive impact to the STEM community."},
    {"profileId": "anthony-luo", "id": "anthony-luo", "name": "Anthony Luo", "imgurl": "AnthonyLuo.jpg", "description": "Hi! I'm Anthony Luo, a sophomore at Saratoga High School. This is my fourth semester teaching public speaking and debate with SVY, and my fourth year doing Public Forum debate with my partner and co-teacher, Skyler. I've participated in debate on a national level in competitions at Berkeley, Yale, Arizona State University, and Kentucky. I'm also in my school's marching band and winter percussion, and in my free time I enjoy listening to music and watching TV shows or movies. I look forward to working with all of you this semester!"},
    {"profileId": "anthony-zhou", "id": "anthony-zhou", "name": "Anthony Zhou", "imgurl": "AnthonyZhou.jpg", "description": "Anthony Zhou is a sophomore at Palo Alto High School. He has been participating in math tournaments since 6th grade. Some of his math achievements include qualifying for AIME, getting distinction on AMC10, and getting first in the nation in math kangaroo. In his free time, he likes to swim and hang out with his friends."},
    {"profileId": "archer-jin", "id": "archer-jin", "name": "Archer Jin", "imgurl": "ArcherJin.jpg", "description": "Archer Jin is a Senior at Gunn High School. He has always been interested in history, especially World War 2, and is passionate about teaching it to others. He has thorough knowledge and experience with history presentations at school and writing essays, so he is able to confidently reteach it to other students. He also enjoys running, reading, and following current events."},
    {"profileId": "arnav-swamy", "id": "arnav-swamy", "name": "Arnav Swamy", "imgurl": "ArnavSwamy.jpg", "description": "Arnav Swamy is a senior at Saratoga High School and this is his 6th semester teaching at SVY. He is a published author of a fantasy novel. In writing, he enjoys journalism and poetry alongside writing short stories. In his free time, he enjoys listening to music and going on long walks."},
    {"profileId": "arthur-ji", "id": "arthur-ji", "name": "Arthur Ji", "imgurl": "ArthurJi.jpg", "description": "Arthur is a senior at Monta Vista High School and will be serving as your co-teacher for Intro to Java this semester. Having joined SVY in 2016, he has continued to teach many courses in the Computer Science department, including Intro to Java and Game Design. His main interests include business, programming, other STEM topics, politics, and economics. He is in DECA and MUN and has previously been a part of Speech and Debate. In his free time, Arthur enjoys reading up on the latest news, playing video games, and watching Youtube videos. He looks forward to meeting all of you and having a great class!"},
    {"profileId": "arthur-zhou", "id": "arthur-zhou", "name": "Arthur Zhou", "imgurl": "ArthurZhou.jpg", "description": "Hi! I am I sophomore at Lynbrook High School. I learned bridge at a summer camp four years ago and have continued to play and improve ever since. I play regularly in many national level tournaments with my partner Michael Hu, and we have won many youth titles as well as represented USA in under 16 competition. Recently, my USA under 16 team took the bronze medal at the Youth World Bridge Team Championships. Unfortunately, this wonderful game is slowly dying out, but I hope that more and more youth can be exposed and keep the bridge community thriving for years to come."},
    {"profileId": "ashley-tsai", "id": "ashley-tsai", "name": "Ashley Tsai", "imgurl": "AshleyTsai.jpg", "description": "Hi! My name is Ashley, and I’m a junior at Mountain View High School. I’ve taken a fast-paced Biology course over the summer and completed Honors Biology. This is my first year being a TA at SVY, and I’m looking forward to teaching and meeting everyone!"},
    {"profileId": "ashok-sheridan", "id": "ashok-sheridan", "name": "Ashok Sheridan", "imgurl": "AshokSheridan.jpg", "description": "Hi, I am an upcoming senior at Monta Vista high school. I enjoy 3D modeling, physics, and playing badminton with my friends. I have done 1 on 1 tutoring in the past and am excited to teach a class this fall!"},
    {"profileId": "audrey-feng", "id": "audrey-feng", "name": "Audrey Feng", "imgurl": "AudreyFeng.jpg", "description": "Hi, I'm Audrey. I'm in ninth grade at the Harker High School and I will be teaching the reading/book club class! I find that reading a good book is not only immersive and interesting, it also helps you learn concepts that are useful in an enjoyable way. I'm personally an avid reader and ejoy reading fantasy books. I play tennis competitively and enjoy reading, baking, and doing arts and crafts in my free time."},
    {"profileId": "audrey-lee", "id": "audrey-lee", "name": "Audrey Lee", "imgurl": "AudreyLee.jpg", "description": "Audrey Lee is going to be a senior at Saratoga High School. Ever since the fifth grade, she has been competing in speech and debate. She has practiced Extemporaneous speaking for three years and competed in many other events including Oratorical Interpretation, Duo Interpretation, Expository, Impromptu, and Public Forum Debate. Audrey has placed at numerous tournaments, such as the Santa Clara University Dempsey Cronin Invitational, Stanford Invitational, and James Logan. In her free time, Audrey enjoys hanging out with her friends, making ceramics, and playing with her cats. She is eager to help her students develop a passion for public speaking."},
    {"profileId": "austin-liu", "id": "austin-liu", "name": "Austin Liu", "imgurl": "AustinLiu.jpg", "description": "Austin Liu is a senior at Los Altos High School who has computer science and Python with Silicon Valley Youth for over four years. He also serves as the VP of Computer Science at Silicon Valley Youth, and this is his ninth semester teaching Python at SVY. He has completed AP Computer Science A with a 5, is in the silver division of USACO, and has published research in network security and machine learning in peer-reviewed journals. Outside of class, Austin’s passions include learning new things, hiking, reading, and programming."},
    {"profileId": "benjamin-owens", "id": "benjamin-owens", "name": "Benjamin Owens", "imgurl": "BenjaminOwens.jpg"},
    {"profileId": "bhuvi-tawari", "id": "bhuvi-tawari", "name": "Bhuvi Tawari", "imgurl": "BhuviTawari.jpg", "description": "Bhuvi is a freshman at Los Altos High School. She is qualified for AIME through the AMC 10 and has made Honor Roll and Distinguished Honor Roll in the AMC 8. She enjoys competitive math and has distinctions in various middle school and high school math competitions as well. In her free time, she enjoys playing badminton, reading, and spending time with friends."},
    {"profileId": "bohong-su", "id": "bohong-su", "name": "Bohong Su", "imgurl": "BohongSu.jpg", "description": "Hello! My name is Bohong Su, a Junior at Valley Christian High School. To me, mathematics is extremely meaningful because it has taught me how to think rigorously and rationally, and of course, math is useful in any STEM-related field. In this calculus course, I will show you guys the magic of math."},
    {"profileId": "brandon-fu", "id": "brandon-fu", "name": "Brandon Fu", "imgurl": "BrandonFu.jpg", "description": "Brandon is a senior at Homestead High School in Cupertino, California. He has been interested in coding since a young age and has experience in Java, HTML, CSS, Javascript, and Python. He has previously taught this class and is looking forward to further expand his teaching experience. In his free time, Brandon enjoys playing sports and partaking in various business activities."},
    {"profileId": "brandon-lin", "id": "brandon-lin", "name": "Brandon Lin", "imgurl": "BrandonLin.jpg", "description": "Brandon Lin is currently a sophomore at Palo Alto High School and this is his fourth semester at SVY. He is proficient in Python and Java, is a USACO Silver qualifier, and scored a 5 on the AP CS A exam. Aside from programming, he enjoys playing clarinet, biking, and badminton."},
    {"profileId": "brianna-wang", "id": "brianna-wang", "name": "Brianna Wang", "imgurl": "BriannaWang.jpg", "description": "Hi, I'm Brianna Wang, and I am a senior at Homestead High School. Physics is an interesting topic that can be applied to everyday life. I really enjoy learning about physics, and I am excited to be teaching about it. My fascination in physics has led me to receive 5 on the AP Physics 1 exam and the AP Physics C exams. In my free time, I enjoy baking, cooking, and painting. I look forward to a great Fall 2022 semester!"},
    {"profileId": "bryan-han", "id": "bryan-han", "name": "Bryan Han", "imgurl": "BryanHan.jpg", "description": "Bryan Han is a 10th grader and AIME qualifier at Saratoga High School. He started to attend math competitions in fifth grade and has achieved DHR in AMC 8 as a fifth grader and AR in AMC 10 as a 7th grader. He has also participated in MathCounts and Mathleague competitions, and qualified to the MathCounts State round. Outside of math, Bryan has a passion for drama and music."},
    {"profileId": "bryan-li", "id": "bryan-li", "name": "Bryan Li", "imgurl": "BryanLi.jpg", "description": "Bryan Li is currently a 10th grader at Saratoga high school. Bryan enjoys competing in math competitions achieving a perfect score in the AMC 8, a Distinguished Honor Roll in the AMC 10, as well as qualifying for aime 4 times. In his free time, Bryan enjoys coding and talking to his friends."},
    {"profileId": "bryan-liu", "id": "bryan-liu", "name": "Bryan Liu", "imgurl": "BryanLiu.jpg", "description": "Hello! My name is Bryan Liu, and I am a Senior at Homestead High School. I am currently involved in my school’s debate club and robotics. I began debate in 5th grade and have been passionate about it ever since. I really enjoy teaching kids and working with them and have been a teacher at SVY for 7 amazing semesters. On my own time, I swim and play water polo for school and club."},
    {"profileId": "bryan-owens", "id": "bryan-owens", "name": "Bryan Owens", "imgurl": "BryanOwens.jpg"},
    {"profileId": "carter-bian", "id": "carter-bian", "name": "Carter Bian", "imgurl": "CarterBian.jpg", "description": "Carter Bian is a junior at Cupertino High School. He participates in USACO Gold competitions, summer programs, and side projects. Specifically, Carter has used C++ for competitive coding, Java to score a 5 on AP Computer Science, Arduino to program a clarinet at UC San Diego’s COSMOS, and HTML for Cupertino High School’s cooking club website. Outside of coding, Carter has found ways to pursue his hobbies in school by acquiring the status of the captain of Cupertino High’s badminton team and president of CHS Cooking Club. This summer, he will be living alongside the residents of San Juan de la Maguana of the Dominican Republic, where he will gain insight on deconstructing poverty while delving into the country’s rich culture."},
    {"profileId": "cayden-gu", "id": "cayden-gu", "name": "Cayden Gu", "imgurl": "CaydenGu.jpg", "description": "My name is Cayden Gu, and I am a senior at Palo Alto High School. From a young age, I have been fasincated with both math and sports, from playing fantasy football to studying Amazon AWS' NextGen stats. Having attended the Wharton Moneyball Training Camp, I've delved into the world of sports analytics, furthering my love for connecting abstract concept to a game defined by physical performance and human emotions. The cross-over between math and humanity has fasinated me in other areas, and I am a 2x TSA TEAMS (Tests of Engineering Aptitude, Mathematics, and Science) National Champion, where I regularly applied math to a myriad of real-world engine problems. I'm also a 3x AIME (American Invitational Mathematics Examination) qualifier. Finally, I recently finished my term as Cadet Commander for my Civil Air Patrol squadron, the US Air Force civillian auxiliary, where I enjoy learning about aerospace and cybersecurity while leading the next generation to uphold the Air Force's customs and courtesies."},
    {"profileId": "charles-li", "id": "charles-li", "name": "Charles Li", "imgurl": "CharlesLi.jpg", "description": "Charles Li is a senior at Los Gatos High School. He has taught Web Design several semesters before. He has experience in HTML, CSS, Python, Javascript, and robotics. For robotics, he took a robotics course in CTY. He enjoys playing sports such as swimming, tennis and volleyball. He currently plays volleyball at MVVC."},
    {"profileId": "chiling-han", "id": "chiling-han", "name": "Chiling Han", "imgurl": "ChilingHan.jpg", "description": "Chiling Han is currently a sophomore at the Harker School. She has been coding in Python since 6th grade and is in the silver division of USACO. Moreover, she received a 5 on the AP Computer Science A exam and is the software director and VEX lead at her school’s FRC club. In addition to Python, Chiling has experience with Java, C++, and C. She has worked on IoT research with a local university’s professor and is also the director of curriculum at another nonprofit organization helping underprivileged children. Furthermore, she has been a workshop speaker at multiple hackathon events. Currently, she is working on an embedded system for localization in GPS-compromised environments at UCSC."},
    {"profileId": "chloe-lee", "id": "chloe-lee", "name": "Chloe Lee", "imgurl": "ChloeLee.jpg", "description": "Chloe is a sophomore at the Harker Upper School. She has gotten full scores on the CAML, ASMA, and MOEMS, and scored high on BAMO, AMC 8, and AMC 10. She has had many impactful teachers in the past, so she hopes to be one herself, by having fun math activities to keep students constantly engaged. In her free time, she does DECA, taekwondo, more math, and science research. This is her second time teaching at SVY, and she's really excited to teach young students!"},
    {"profileId": "chris-lee", "id": "chris-lee", "name": "Chris Lee", "imgurl": "ChrisLee.jpg", "description": "Chris Lee is currently a senior at Lynbrook High School. He's been teaching at SVY since 2018, and has been doing working with 3D design, and 3D printing for 5 years now. He's also interested in Rubik's Cubes, plays guitar, and volleyball."},
    {"profileId": "cindy-li", "id": "cindy-li", "name": "Cindy Li", "imgurl": "CindyLi.jpg", "description": "Cindy Li is currently a senior at Los Gatos High School. She has taken numerous classes and is well-educated about programming languages such as Python, C++, Java, and HTML. She also has substantial experience in working with students: in addition to being involved in multiple debate tournaments and other events involving public speaking, Cindy has also successfully taught several semesters of both Introduction to and Advanced Web Design at SVY. Her creativity and sensitivity allow her to cater to students’ needs and ensure a not only fun but also educational learning experience. In her free time, outside of programming, Cindy also enjoys graphic design, swimming, art, and music."},
    {"profileId": "cindy-xu", "id": "cindy-xu", "name": "Cindy Xu", "imgurl": "CindyXu.jpg", "description": "Cindy Xu is a senior at Lynbrook High School who is very passionate about public speaking and debating. She has 6 years of speech and debate experience, having competed in Public Forum debate, Lincoln-Douglas debate, and Oratorical Interpretation Speaking. Her teaching experience includes volunteering at multiple debate camps to teach students how to debate by helping them improve their arguments and speaking. During her junior year, she received a bid to the 2019 Tournament of Champions in Public Forum debate. She has taught Public Speaking and Debate for 4 sessions at SVY and is excited to teach this class again!"},
    {"profileId": "claire-cheng", "id": "claire-cheng", "name": "Claire Cheng", "imgurl": "ClaireCheng.jpg"},
    {"profileId": "clark-wang", "id": "clark-wang", "name": "Clark Wang", "imgurl": "ClarkWang.jpg", "description": "Clark is a junior from Lynbrook High School, and has taught US History at SVY for four semesters. As an international student who came to the US in 2016, He has utilized his linguistic advantages and the timeliness of adapting to a new environment. He has also dedicated his time to competitive choral music for 9 years (and counting), and watches soccer, table tennis, and darts in much of his spare time."},
    {"profileId": "crystal-zhu", "id": "crystal-zhu", "name": "Crystal Zhu", "imgurl": "CrystalZhu.jpg", "description": "Crystal Zhu is a senior at Lynbrook High School. Since a very young age, she has enjoyed reading and writing short stories. As the co-Editor-in-Chief of her school newspaper, a California Arts Scholar and attendee of the Northwestern Journalism Institute, she is excited to pass on her passion! Besides writing, she also loves eating. Crystal will be attending Northwestern University this fall."},
    {"profileId": "cynthia-jia", "id": "cynthia-jia", "name": "Cynthia Jia", "imgurl": "CynthiaJia.jpg", "description": "Hello there! I’m Cynthia Jia, a senior at Los Altos High School. As a biology enthusiast, I self-studied AP Biology and scored a 5, ran the Journal Club where scientific literatures are translated into common English. I am also a research intern running investigation surrounding narcolepsy-related T-cell receptors at Stanford. Biology has been and is still my greatest teacher. Exploring this field, I learned how to troubleshooting, think critically, and apply knowledge to understand the world around us —— skills that are lifelong beneficial. Seriously, biology is a fun subject."},
    {"profileId": "daniel-wu", "id": "daniel-wu", "name": "Daniel Wu", "imgurl": "DanielWu.jpg", "description": "Hello! I'm Daniel, and I've also been a Public Speaker when you were all embryos. I love tennis, biking, and reading, and unlike Minh, I don't assiduously avoid working out. I am forced to deal with all of Minh's slip ups, which are quite a few, and you can watch Minh get reminded by me every class to do something. Minh's chaotic energy is helpful in debate, and we've competed in tournaments as Public Forum partners and argued some unusual cases that you'll get to look at. Fun fact: I have a higher Chem grade than Minh (not such a high bar)"},
    {"profileId": "danni-deng", "id": "danni-deng", "name": "Danni Deng", "imgurl": "DanniDeng.jpg", "description": "Hello! My name is Danni Deng and I'm a junior in Saratoga highschool. I am currently taking AP Art."},
    {"profileId": "darren-zhan", "id": "darren-zhan", "name": "Darren Zhan", "imgurl": "DarrenZhan.jpg", "description": "Hi! My name is Darren Zhan, I am a junior at Mills High School. I will be teaching World History. My interest in World History started when my parents taught me about the Qing Dynasty and World Wars, and their impact on China. I read history on my own, learning about the Spring and Autumn Period, major dynasties, Greek/Roman Empires, and modern European history. I am a VP in my High School Debate Team and I participated in many tournaments. I also play tennis for my school team."},
    {"profileId": "dennis-han", "id": "dennis-han", "name": "Dennis Han", "imgurl": "DennisHan.jpg", "description": "Dennis is a senior at Lynbrook High School. He is passionate about teaching and learning science, specifically nursing. He loves to give back to the community through many ways including her contributions to guidance and mentorship for middle school students, his leadership in non-profit organizations in the nursing field, as well as volunteering at local hospitals. Outside of STEM, Dennis enjoys playing video and board games, watching TV shows and sports, and playing spike ball."},
    {"profileId": "derek-li", "id": "derek-li", "name": "Derek Li", "imgurl": "DerekLi.jpg", "description": "Derek Li is a current senior at Lynbrook High School. He has been a passionate singer since a young age and has received professional voice training for about 10 years. Since 2020, he has become an avid composer who wants to share his music. In 2023, Derek won First Prize Winner in Grand Prize Virtuoso and won First Place in the USIMC Young Artist Award. During 2022 he won First Prize in the American Virtuoso International Music Competition, the First Prize of the American Fine Arts Festival. Before that, he has won the First Place Winner and 2nd Place Winner for solo and duo performances in the American Protege International Competition from 2021-2022. Derek has performed in Davies Symphony Hall of San Francisco, Carnegie Hall in New York, and also in Salzburg and Beijing. Derek received a 5 on AP Music Theory Exam in 9th grade and passed RCM Voice Level 10 earlier this year. Derek hopes to share his understanding and knowledge about music to students who either just begin to be exposed to complex music jargons or who are already very experienced in music. He hopes to help the students to compose their own music and further their passion into the music world. In his free time, Derek enjoys playing soccer and watching anime."},
    {"profileId": "derrick-cai", "id": "derrick-cai", "name": "Derrick Cai", "imgurl": "DerrickCai.jpg", "description": "Derrick Cai is a freshman attending Lynbrook High School, and has played basketball from a very young age. He has grown up participating in a variety of clinics, clubs, and teams, including West San Jose NJB, where he was selected on the All Net team from grade 5-8. In middle school, he played for Miller Middle School, where they championed with a nearly undefeated record and he was selected MVP. He has played in SVBC, a large asian league club, for over 3 years, where he has won many championships in both asian league and AAU. Currently, he plays as the starting point guard on the Lynbrook High JV team. He hopes to guide younger players to develop skills and find their passion for the sport he loves and enjoys."},
    {"profileId": "dylan-zhang", "id": "dylan-zhang", "name": "Dylan Zhang", "imgurl": "DylanZhang.jpg", "description": "Dylan is a senior at Lynbrook High School who loves computer science. He is proficient in many languages, including Java, Python, C++, and Matlab, and he is also involved in the USACO competition. Dylan is strong in math and physics as well, and he is a 2019 USAPhO medalist. Outside of school, Dylan enjoys playing tennis and the piano."},
    {"profileId": "edward-feng", "id": "edward-feng", "name": "Edward Feng", "imgurl": "EdwardFeng.jpg", "description": "Edward Feng is currently a senior at Stratford Preparatory in his 3rd year of teaching at SVY. He has prior coding and math experience as the founding president of his school’s math team and a 5 on the APCSA exam, as well as teaching experience as a taekwondo instructor for 2 years. He loves to read, code, and draw in his free time."},
    {"profileId": "edward-zhang", "id": "edward-zhang", "name": "Edward Zhang", "imgurl": "EdwardZhang.jpg", "description": "Edward Zhang is an 12 grader at Irvington HIgh School. He really enjoys playing badminton and has played badminton since he was six years old. In total, he has won 5 national titles in doubles."},
    {"profileId": "eileen-zhu", "id": "eileen-zhu", "name": "Eileen Zhu", "imgurl": "EileenZhu.jpg", "description": "Hi guys! My name is Eileen and I’m a senior at Lynbrook High. This will be my 7th semester co-teaching Competitive speech, and I'm very excited to get to know all of you! I’ve participated in several speech tournaments in OO and Impromptu, and received 1st in Public Speaking in Bay Section FBLA, as well as placing in states. The competitive aspect is fun, but I also hope to help students communicate well enough so that everyone around them wants to listen to what they have to say. I’m looking forward to meeting everyone!"},
    {"profileId": "elliot-seo", "id": "elliot-seo", "name": "Elliot Seo", "imgurl": "ElliotSeo.jpg", "description": "Hello, my name is Elliot Seo. I am a tenth grader. I have always enjoyed mathematics, as I enjoy solving difficult challenges. I also have experience in math competitions such as the Math Kangaroo, MathCounts, and AMC tests. My hobbies include reading mystery novels like the Sherlock Holmes novels, watching sci-fi movies, robotics, and playing tennis."},
    {"profileId": "emilie-chan", "id": "emilie-chan", "name": "Emilie Chan", "imgurl": "EmilieChan.jpg", "description": "Emilie is currently a sophomore at Monta Vista High School. She is currently USACO Silver and enjoys the many challenges that come with programming. Her main activities includes being a programmer for a 3-time World Qualifier VEX Robotics team, playing badminton, and hanging out with her friends."},
    {"profileId": "emily-chang", "id": "emily-chang", "name": "Emily Chang", "imgurl": "EmilyChang.jpg", "description": "Hi! My name is Emily Chang, and I am currently a senior at Valley Christian High School and have had an avid interest in art since childhood. I have won the Scholastics Gold Key Award for an art piece in 2020 and three other honorable mention awards as well, and scored a 5 on the AP Art exam in 2022. I've been doing art for almost 10 years and at an AP level for about 4 years. Previously, I was a TA for art outside of SVY; within SVY, I've taught 2 successful semesters of this art course and have been a TA in AMC level math. I hope to influence students to appreciate more the effort artists put in to create art or even continue art in the future."},
    {"profileId": "emily-yang", "id": "emily-yang", "name": "Emily Yang", "imgurl": "EmilyYang.jpg", "description": "Emily Yang is an eighth grader at The King’s Academy who has been studying creative writing since the age of eight. She now primarily writes poetry, though she also enjoys fiction, personal narratives, and memoirs. She has participated in newspaper clubs throughout middle school and has been published in writing journals. She is super excited to be part of SVY this semester and looks forward to continuing to grow as a writer! Outside of writing, she enjoys singing and playing golf."},
    {"profileId": "emma-lu", "id": "emma-lu", "name": "Emma Lu", "imgurl": "EmmaLu.jpg", "description": "Emma is a sophomore at Homestead High School. Passionate about writing, she is currently taking a pre-journalism course at school. Additionally, she is part of her school’s FBLA club and is competing in Broadcast Journalism and Business Communication, a competition focused on grammar and writing style. In her spare time, Emma enjoys dancing, reading historical fiction, traveling, and hanging out with her friends."},
    {"profileId": "emma-xia", "id": "emma-xia", "name": "Emma Xia", "imgurl": "EmmaXia.jpg", "description": "Hi, my name is Emma, and I'm a 6th grader at Oak Avenue Elementary School. I am a counselor in a MiT program and was recommended by my math coach. Last year I participated in a Mathlete program, and due to my high performance in it, I was awarded Mathlete of the Year. I also participated in the AMC 8 this year. During my free time, I play flute for California Youth Symphony and play volleyball for Mountain View Volleyball Club. I have also taken many SVY classes for math. I am excited to help with Sean's Discrete Math class!"},
    {"profileId": "eric-ren", "id": "eric-ren", "name": "Eric Ren", "imgurl": "EricRen.jpg"},
    {"profileId": "eric-wang", "id": "eric-wang", "name": "Eric Wang", "imgurl": "EricWang.jpg", "description": "Eric is a senior at Lynbrook High School, and this is his eighth semester teaching at SVY having taught both AMC 8 Basic and Advanced. He has been doing competition math since the start of 7th grade and has achieved numerous awards including being a 5-time AIME qualifier, an AMC 10 DHR member, and a USAJMO qualifier. Along with math, Eric also enjoys coding and playing soccer."},
    {"profileId": "eric-yang", "id": "eric-yang", "name": "Eric Yang", "imgurl": "EricYang.jpg", "description": "Eric is a current junior at Lynbrook High School. Starting his freshman year, he has studied Java and got a 5 on the AP Computer Science test. In addition to Java, Eric has learned Python through a De Anza College and C through COSMOS. Eric has taught Intermediate Java for 2 semesters and was TA for Arthur’s Java class in the 2017 spring semester. Besides computer science, Eric is also interested in math, earning a 5 on AP Calculus BC and taking math competitions such as AMC’s, Math Olympiads, and CAML’s. Outside of school Eric plays piano and is a leader in his Boy Scout troop. In his free time, he likes to socialize with friends and shop for clothing."},
    {"profileId": "ethan-chen", "id": "ethan-chen", "name": "Ethan Chen", "imgurl": "EthanChen.jpg"},
    {"profileId": "ethan-lin", "id": "ethan-lin", "name": "Ethan Lin", "imgurl": "EthanLin.jpg", "description": "Hi! I’m Ethan Lin and I’m a senior at Gunn High School. I have played go since I was 6 years old, and I enjoy it because of how it forces one to use a lot of strategy and brain power in order to play the game well. In Asia, I am ranked as at 4 dan. Some activities I enjoy outside of school are tennis, competition math, and robotics (and of course go). I’ve been teaching Go for the past year, both at SVY and elsewhere. Since Go does not have a lot of popularity in the United States, I hope to expose more youth to it and keep this game thriving."},
    {"profileId": "ewan-webster", "id": "ewan-webster", "name": "Ewan Webster", "imgurl": "EwanWebster.jpg", "description": "Hi, I'm Ewan, and I'm a high school Senior attending Woodside Priory School. I'm the founder and coach of my school's debate team, and I've debated at the national level for 5 years. One of my greatest interests is developing kids into confident public speakers, and I've been doing so at Silicon Valley Youth for 6 Semesters. I'm super excited for this upcoming semester!"},
    {"profileId": "florence-wei", "id": "florence-wei", "name": "Florence Wei", "imgurl": "FlorenceWei.jpg", "description": "Florence Wei is a senior at Saratoga High School. This past summer, she attended Kenyon Review Young Writers Workshop and the Iowa Young Writers Studio. Florence is an entertainment editor for the Saratoga Falcon journalism program, as well as an editor on the Saratoga Soundings staff. She has won a gold key from Scholastic Alliance for Young Artists & Writers, as well as the NCTE Achievement Awards in Writing first-class distinction. When she isn't reading or writing, she enjoys playing the cello and listening to classical music."},
    {"profileId": "frances-zhuang", "id": "frances-zhuang", "name": "Frances Zhuang", "imgurl": "FrancesZhuang.JPG"},
    {"profileId": "fred-zhang", "id": "fred-zhang", "name": "Fred Zhang", "imgurl": "FredZhang.jpg", "description": "Fred Zhang is currently an 8th grader at Pleasanton Middle School. His favorite subjects are Math, Reading, and History. In his free time, he likes to exercise and hang out with friends. Fred began his teaching journey in 5th grade, where he has continued helping students thrive as a TA. By teaching younger students, he hopes to create a positive childhood experience for many to thrive in the future."},
    {"profileId": "gabrielle-he", "id": "gabrielle-he", "name": "Gabrielle He", "imgurl": "GabrielleHe.jpg", "description": "Hey guys! I’m Gabrielle, a sophomore at Lynbrook High School. I’ve been participating in public speaking events for over 5 years, having done many different types of speech and debate. I have experience in events such as Public Forum and Lincoln Douglass debate, as well as impromptu, original oratory, SPAR, and many more types of speech, and I'm currently an active member of my schools Model United Nations program. I’m excited to meet you all soon in class!"},
    {"profileId": "george-wang", "id": "george-wang", "name": "George Wang", "imgurl": "GeorgeWang.jpg"},
    {"profileId": "gilbert-feng", "id": "gilbert-feng", "name": "Gilbert Feng", "imgurl": "GilbertFeng.jpg"},
    {"profileId": "grace-li", "id": "grace-li", "name": "Grace Li", "imgurl": "GraceLi.jpg", "description": "Nice to meet you, I am Grace Li. I am a senior at Palo Alto high school. I have been the teacher for this biology class for 4+ semesters now, and I teach with Sharon Zhu. I am currently an AP biology student and apply the concepts I teach in this class to my own AP biology course as well—which you guys hopefully will do as well in future biology courses. I hope you guys learn a lot through this class!"},
    {"profileId": "grace-wong", "id": "grace-wong", "name": "Grace Wong", "imgurl": "GraceWong.jpg", "description": "Grace Wong is a student at The King’s Academy who enjoys studying history to learn about the lives of people in the past. She has scored a 5 on the AP exams for World History and US History. At school, Grace tutors students in history, English, and biology, and is an editor for 2 literary magazines. Additionally, she interns for the non-profit Pacific Atrocities Education, researching Japanese war crimes during WWII. Besides history, Grace also enjoys creative writing, music, and boba."},
    {"profileId": "hannah-hu", "id": "hannah-hu", "name": "Hannah Hu", "imgurl": "HannahHu.jpg", "description": "Hannah currently goes to Fletcher, a middle school in Palo Alto, and she likes to do a variety of things, from reading to percussion, basketball and art. This is Hannah’s third semester, and she hopes to enjoy this one just as much as she enjoyed the first two."},
    {"profileId": "hannah-zhang", "id": "hannah-zhang", "name": "Hannah Zhang", "imgurl": "HannahZhang.jpg", "description": "Hanyu, or Hannah Zhang, is a sophomore at Lynbrook High School and is starting her fourth semester with SVY. She has achieved several mathematical awards including a full score on AMC 8, AIME qualifier, etc. On top of math, she takes part in swimming and running. Along with sports, she also enjoys coding, photography, theme parks, and watching cdramas."},
    {"profileId": "helen-li", "id": "helen-li", "name": "Helen Li", "imgurl": "HelenLi.jpg", "description": "Helen Li is a senior at Homestead High School. She loves humanities subjects and all forms of artistic expression. She is an avid reader and writer, and she has written countless poems and short stories, both recreationally and for writing magazines. Her achievements include receiving a Topical Winner award from Live Poets Society and publications in magazines such as Write the World, Scribere, and Frontier. Aside from literature, Helen loves making music and trying new things. She looks forward to teaching and spending time with the students in exploring literature and creative writing."},
    {"profileId": "henry-huang", "id": "henry-huang", "name": "Henry Huang", "imgurl": "HenryHuang.jpg", "description": "Hi I’m Henry. I’m currently in ninth grade at Los Altos High School. I currently live in Los Altos, and have for around 7 years. I started programming during 4th grade, and continue to do so. I learned many coding languages, such as python and java. I’ve been a part of SVY for around a year now, and continue to do so."},
    {"profileId": "henry-wang", "id": "henry-wang", "name": "Henry Wang", "imgurl": "HenryWang.jpg", "description": "Henry Wang is a rising sophomore at Lynbrook High School. He has qualified for the USAJMO, is a three-time AIME qualifier, and has made AMC 8 DHR twice. He also competes in USACO and vex robotics competitions. In his free time, he enjoys playing soccer, brawl stars, chess, and hanging out with friends."},
    {"profileId": "henry-ying", "id": "henry-ying", "name": "Henry Ying", "imgurl": "henryying.jpg"},
    {"profileId": "ian-lee", "id": "ian-lee", "name": "Ian Lee", "imgurl": "IanLee.jpg", "description": "Ian Lee teaches Introduction to Chemistry for 6th to 10th graders with a focus on making science click for everyone. He scored a 5 on the AP Chem exam and brings both knowledge and real enthusiasm to class. In his free time, he enjoys playing soccer with his friends."},
    {"profileId": "isaac-li", "id": "isaac-li", "name": "Isaac Li", "imgurl": "IsaacLi.jpg", "description": "Hello! I’m Isaac Li, a junior at Monta Vista High School. I am very passionate about physics, and I earned a 5 on the AP Physics 1 exam. Outside of school, I enjoy coding, playing badminton, and cycling with my friends. I truly look forward to teaching this class and spreading my love of physics!"},
    {"profileId": "isabella-shen", "id": "isabella-shen", "name": "Isabella Shen", "imgurl": "IsabellaShen.jpg", "description": "Isabella is a senior at Archbishop Mitty High School and this is her seventh semester with SVY. She is passionate about coding and is proficient in Python, Java, and C++. She has a 5 on AP CSA, is a USACO Gold qualifier, and also participates in bioinformatics research. Besides programming, she enjoys playing soccer, reading, and rock climbing."},
    {"profileId": "isabella-wang", "id": "isabella-wang", "name": "Isabella Wang", "imgurl": "IsabellaWang.jpg", "description": "Hello! My name is Isabella Wang and I'm a junior in highschool. I love art and have been drawing for eight years now!"},
    {"profileId": "isabella-watson", "id": "isabella-watson", "name": "Isabella Watson", "imgurl": "IsabellaWatson.jpg", "description": "Hello! My name is Isabella Watson and I am a senior at Valley Christian High School. This is my fourth semester teaching Introduction to Economics at SVY. I am currently an active member of my school’s DECA club, working as a VP and competing at state and international conferences. I have attended two economics summer programs with the Foundation for Teaching Economics. I also have experience working at a startup dedicated to teaching personal finance and entrepreneurship to elementary/middle schoolers. Outside of SVY, I enjoy reading and listening to music. My favorite music artist at the moment is Lana Del Rey. I’m super excited to be teaching this class again and meeting new students!"},
    {"profileId": "isaiah-sit", "id": "isaiah-sit", "name": "Isaiah Sit", "imgurl": "IsaiahSit.jpg", "description": "Isaiah is a sophomore at Lynbrook High School with a lifelong passion for all things history. He is an experienced teacher, having taught multiple classes including four semesters of US History at SVY. His ambition as teacher is to debunk the horrifyingly wrong history-is-boring myth and make history interesting and engaging."},
    {"profileId": "jakin-shen", "id": "jakin-shen", "name": "Jakin Shen", "imgurl": "JakinShen.jpg", "description": "Jakin Shen is a senior at Fremont High School. He has been involved in competitive math since middle school, and has participated in contests such as AMC, AIME, and USAJMO. Outside of math, Jakin enjoys reading, volunteering, and playing music."},
    {"profileId": "jasmine-hou", "id": "jasmine-hou", "name": "Jasmine Hou", "imgurl": "JasmineHou.jpg", "description": "Jasmine Hou is currently a junior at Lynbrook High School. After taking several coding classes in middle school, she went on to take AP Computer Science A and still continues to develop her interest for the subject. She is currently a USACO Gold competitor. Through her time at SVY, she hopes to develop herself as a leader and as an individual, as well as give back to the community. Other interests consist of business, music, math, and other STEM related topics. In her free time, she enjoys watching anime and playing with her dog."},
    {"profileId": "jasmine-yuan", "id": "jasmine-yuan", "name": "Jasmine Yuan", "imgurl": "JasmineYuan.jpg", "description": "Jasmine is a senior at Homestead High School. She has competed and placed in competitions such as FBLA, National Econ Challenge, and Diamond Challenge, winning many state and national level awards. She has attended both the LaunchX entrepreneurship program and Wharton's Leadership in the Business World program, and has held leadership positions in business clubs. She also has entrepreneurship experience creating her own startups. Outside of SVY, she enjoys traveling, playing tennis, and spending time with friends. This is her seventh semester with SVY and she's excited to help students start their business journey!"},
    {"profileId": "jason-kuo", "id": "jason-kuo", "name": "Jason Kuo", "imgurl": "JasonKuo.jpg", "description": "Hello! I am a 10th grader at Basis Independent Silicon Valley. This is my fourth semester as a teacher, and my sixth at SVY. I've only taught Intro to Business and Intro to Economics at SVY, but I have over 50 hours of teaching LD at my school and in my community. I have done Lincoln Douglas for multiple years, qualifying for the Tournament of Champions and semi-finaling Stanford last year. I look forward not only to helping students learn the fundamentals of LD, but also to learning from them. In my free time, I enjoy reading books and listening to music."},
    {"profileId": "jason-rong", "id": "jason-rong", "name": "Jason Rong", "imgurl": "JasonRong.jpg", "description": "Hi! My name is Jason and I'm currently an 8th grader at Miller Middle School and this is my first semester teaching. I love debate and have been competing since 7th grade. Some other things I like to do are reading, writing, basketball, and playing Clash Royale."},
    {"profileId": "jason-yang", "id": "jason-yang", "name": "Jason Yang", "imgurl": "JasonYang.jpg"},
    {"profileId": "jeffrey-tian", "id": "jeffrey-tian", "name": "Jeffrey Tian", "imgurl": "JeffreyTian.jpg", "description": "Jeffrey Tian is a junior at Monta Vista High School. In addition to his programming experience, he has gotten a 5 on the AP Physics 1 exam as well as qualified for the AIME twice. He has previously taught Web Design for Silicon Valley Youth and has plenty of experience in teaching and tutoring. In his free time, Jeffrey enjoys playing baseball and basketball. He is excited to teach Java this year and is eager to pass on his knowledge to his students."},
    {"profileId": "jeremy-wang", "id": "jeremy-wang", "name": "Jeremy Wang", "imgurl": "JeremyWang.jpg", "description": "Jeremy Wang is a high school junior. He has played Go since the age of 6, and is ranked 2 dan (2 段). He has taught at SVY for 3 semesters, and looks forward to interacting with kids and teaching them about this amazing game. Outside of Go, he enjoys doing debate and playing the violin."},
    {"profileId": "jerry-ying", "id": "jerry-ying", "name": "Jerry Ying", "imgurl": "JerryYing.jpg", "description": "My name is Jerry. I am a ninth grader at Los Altos High School. I have been programming since I was in fifth grade. It started as something I did for fun, but then I started becoming more serious about it in seventh grade. I learned many programming languages, mainly python. I look forward to working with you."},
    {"profileId": "jiajing-liang", "id": "jiajing-liang", "name": "Jiajing Liang", "imgurl": "JiajingLiang.jpg", "description": "Hi! I’m Jiajing, a 15-year-old sophomore from Cupertino, California. I’ve been studying piano for nearly a decade. Music has been a huge part of my life, and I’ve been fortunate to receive the 2024–2025 First Year Scholarship from the Chopin Foundation of the United States. I was also named the 2025 Southwest Division Alternate in the Senior Piano Duet category at the MTNA competition and had the amazing opportunity to perform in the Music@Menlo Young Performers Program this summer. Over the years, I’ve won many piano competitions, including the MTAC Solo and Concerto Competitions, CAPMT Contemporary and Honors Competitions, USOMC, USIMC, Steinway Junior Piano Competition, Chicago International Competition, Henry and Carol Zeiter Piano Competition, San Francisco Chopin Competition and so on. I’ve also been a state champion in the MTAC and CAPMT competitions. Outside of piano, I play bassoon in my school band and enjoy writing. I’ve received Scholastic Art & Writing Awards for my reflections on music. In my free time, I like playing tennis and video games with friends and reading sci-fi novels. I'm thrilled to join SVY and excited for all the learning and growth we’ll experience together this semester!"},
    {"profileId": "jocelyn-tan", "id": "jocelyn-tan", "name": "Jocelyn Tan", "imgurl": "JocelynTan.jpg", "description": "Hello! My name is Jocelyn Tan, and I am a sophomore at Leigh High School. I am currently competing in varsity Lincoln Douglass. At my first tournament, I received a top ten speaker award, and I competed in the Cal Invitational at UC Berkeley in 2020. I also recently won silver at Modern Brain’s Season Opener. Outside of LD, I have had some experience in Public Forum debate as well as Extemporaneous speech. Speech and debate have been part of my life for as long as I can remember, and I hope to help my students gain confidence in their own speaking skills as well!"},
    {"profileId": "joey-he", "id": "joey-he", "name": "Joey He", "imgurl": "JoeyHe.jpg", "description": "My name is Joey He and I am a very hard working, empathetic, persevering student at Homestead High School. I’ve self studied for the AP Computer Science exam, studied python, c, databases, and advanced Java at mission, and am currently interning at Celential.ai, a startup in the Silicon Valley. In addition, I’ve done community service through piano, and co-founding Onclass, a non profit teaching service."},
    {"profileId": "joshua-si", "id": "joshua-si", "name": "Joshua Si", "imgurl": "JoshuaSi.jpg"},
    {"profileId": "joshua-zhu", "id": "joshua-zhu", "name": "Joshua Zhu", "imgurl": "JoshuaZhu.jpg", "description": "Joshua Zhu is a Sophomore at Proofs School. He’s been coding for five years, and tinkering around with machine learning for one and a half years now. He has completed a college level course in ML and taught a class in it too. He is particularly interested in reinforcement learning, and he plans to try to find something useful for it to solve. Other hobbies include playing the violin and learning to tell stories."},
    {"profileId": "julia-zhao", "id": "julia-zhao", "name": "Julia Zhao", "imgurl": "JuliaZhao.jpg", "description": "Julia Zhao is currently a sophomore at Gunn High School. She has acted as a TA for this course since 2017, and has subbed in for the teacher before. This opportunity has allowed to to combine her love of problem solving and teaching. Throughout the years, she has actively participated in the AMC series contests. She is also the facility coordinator for the Gunn classroom who organizes the classroom rentals. Outside of SVY, Julia enjoys playing badminton."},
    {"profileId": "julie-chen", "id": "julie-chen", "name": "Julie Chen", "imgurl": "JulieChen.jpg", "description": "Hello there! I’m Julie, a rising 10th grader from Gunn High School, and I will be your teacher for this course along with Angeline, my debate partner at the Gunn Public Forum Debate branch. We’ve competed in multiple tournaments this season, including our club one which we won. In addition, I’ve been a member of the Model UN Club for three years now as well. This summer, I’m also extremely honored to be taking an internship at the San Francisco government. Outside of academics, I also enjoy performing in theatre, creative writing, and reading. I’m so excited to work with you all!"},
    {"profileId": "justin-gu", "id": "justin-gu", "name": "Justin Gu", "imgurl": "JustinGu.jpg", "description": "My name is Justin Gu, and I am a senior at Palo Alto High School. I am particularly interested in sports analytics, which leads me to help students learn math through the lens of sports. Growing up, I was always captivated by players’ statistics in sports, and I would often delve into the numerical side of playing Madden, trading football cards, and playing fantasy football. Pursuing sports analytics, I attended the Wharton Moneyball Training camp, started the Sports Analytics Club at my high school, and then returned to the Wharton Moneyball Academy to dive deeper into sports analytics. Outside of math, data, and sports, I enjoy creative writing, and I am also an editor-in-chief of The Campanile, Palo Alto High School’s school newspaper. In my free time, I listen to music and stay up-to-date on sports news."},
    {"profileId": "kaitlyn-wang", "id": "kaitlyn-wang", "name": "Kaitlyn Wang", "imgurl": "KaitlynWang.jpg", "description": "Kaitlyn is a sophomore at the Harker Upper School. Kaitlyn Wang has taught AMC classes at SVY for 3 years now and enjoys designing fun, competitive classroom activities to motivate her students and inspire passion among them for the art of problem solving. She qualified for AIME and knows the ins and outs of AMC’s. In her free time, she enjoys business, art, environmental science research, skiing, and getting boba with her friends."},
    {"profileId": "kevin-shi", "id": "kevin-shi", "name": "Kevin Shi", "imgurl": "KevinShi.jpg", "description": "Kevin Shi is a senior at Palo Alto High School. He has participated in competitive math for more than 5 years, and competed in contests such as MathCounts, AMC 8/10/12, AIME, and USAMO. This is his eighth semester teaching at SVY. In his free time, Kevin enjoys reading, music, and programming."},
    {"profileId": "kevin-wang", "id": "kevin-wang", "name": "Kevin Wang", "imgurl": "KevinWang.jpg", "description": "Kevin Wang is a senior at Harker High School and has been an avid math competitor since elementary school. His passion for math has led him to qualify for the AIME four times and USAMO, whereas his interest in computer science has led him to qualify for gold in USACO. As a young math competitor, Kevin had many impactful mentors that helped cultivate his passion for problem solving. Therefore, he hopes to have a similar impact on the students he teaches. For the past three years, he has taught AMC 8 and aims to continue developing student passion as a part of SVY. In his free time, he enjoys playing basketball, reading philosophy, and doing DECA."},
    {"profileId": "khadijah-ismail", "id": "khadijah-ismail", "name": "Khadijah Ismail", "imgurl": "KhadijahIsmail.jpg", "description": "Hey guys! My name is Khadijah and I am a sophomore at Notre Dame San Jose. My speech journey began around 4 years ago where I competed in various events such as impromptu, LD, and OO. Currently, I have qualified to States, attending all CFL tournaments, won first in Impromptu at La Reina Invitational and other smaller achievements. I'm so excited to get to know you all and teach you the ropes of competitive speech!"},
    {"profileId": "kiara-zhou", "id": "kiara-zhou", "name": "Kiara Zhou", "imgurl": "KiaraZhou.jpg", "description": "Kiara Zhou is currently a 8th grader at Fisher Middle School. She enjoys learning code and discovering how to apply it. Her interest started when she took several computer science courses at SVY."},
    {"profileId": "kurn-sundaram", "id": "kurn-sundaram", "name": "Kurn Sundaram", "imgurl": "KurnSundaram.jpg", "description": "Hey everyone, my name is Kurn and I'm super excited to be teaching this semester for speech and debate. I've been competing since I was a freshman in high school, so for about two years now. Some things I enjoy doing are watching thrillers, hanging out with friends, and going on long late night walks."},
    {"profileId": "kyleen-liao", "id": "kyleen-liao", "name": "Kyleen Liao", "imgurl": "KyleenLiao.jpg", "description": "Kyleen Liao is currently a senior at Saratoga High School who is passionate about programming and teaching. She is currently SVY's VP of CS after teaching Introduction to Java at SVY for the past 4 years. Kyleen has 6 years of Java and robotics experience. Kyleen is also a competitive programmer and performs research in machine learning, winning awards at the Synopsys Science Fair and the California Science and Engineering Fair. Outside of STEM, Kyleen enjoys music, writing, and reading."},
    {"profileId": "lang-feng", "id": "lang-feng", "name": "Lang Feng", "imgurl": "LangFeng.jpg", "description": "Lang Feng is an eighth-grade student at Challenger School with a strong passion for STEM. He actively participates in academic competitions such as Science Bowl, MathCounts, Math League, and the AMC 8 and AMC 10. Beyond academics, Lang is engaged in extracurricular activities, including playing classical guitar and competing in a soccer club. In his free time, he enjoys reading, playing chess, and exploring web programming."},
    {"profileId": "lauren-zhuang", "id": "lauren-zhuang", "name": "Lauren Zhuang", "imgurl": "LaurenZhuang.jpg", "description": "Lauren Zhuang is a junior at Basis Independent Silicon Valley who is passionate about teaching and loves learning various STEM subjects. She is well-versed in Java and familiar with AP-level computer science courses. Outside of school, Lauren dedicates much of her free time to fencing epee, baking, and listening to music."},
    {"profileId": "leo-weng", "id": "leo-weng", "name": "Leo Weng", "imgurl": "LeoWeng.jpg", "description": "Currently a sophomore at Leigh High School. He has several years of public speaking and competitive debate experience. Leo achieved first place in team debate at the World Scholar's Cup and also competes at WSC internationally. He has multiple years of Leadership experience and held the position of treasury at high school."},
    {"profileId": "leo-yang", "id": "leo-yang", "name": "Leo Yang", "imgurl": "LeoYang.jpg", "description": "Leo Yang is currently a senior at Lynbrook High School. He has been with SVY since 2016 and has taught courses ranging from US History, Basketball, Java, and DECA/FBLA. He is excited to teach Poetry this semester, and to spread his knowledge of poetry and literature to students interested in this wonderful craft while preparing them for future literature courses. e enjoys a good puzzle, as well as soccer and video games. Leo looks forward to teaching and spending time with the students in learning the art of poetry."},
    {"profileId": "leyang", "id": "leyang", "name": "Leyang", "imgurl": "Leyang.jpg"},
    {"profileId": "lily-ogawa", "id": "lily-ogawa", "name": "Lily Ogawa", "imgurl": "LilyOgawa.jpg", "description": "Hi! My name is Lily Ogawa and I am a junior at Gunn high school. I am super excited to teach this class and get to know you all! I have competed in debate for over 4 years; I have experience in public forum, parliamentary, Japanese policy and world schools debate. Some of my achievements include: Octofilanists at National Speech and Debate Competition, champion of a national tournament in Japan (HPDU), and broke at several tournaments."},
    {"profileId": "lucas-lum", "id": "lucas-lum", "name": "Lucas Lum", "imgurl": "LucasLum.jpg", "description": "Lucas is a junior at The Harker School and is starting his 7th semester at SVY. He is a math enthusiast and has qualified for AIME since 7th grade and represented his school in high school math tournaments. He is also proficient in Python, Java, C++, and a broad range of AI related technologies which he is actively using towards both his internship at UCSF and his personal research. Besides programming and math, he loves developing multiplayer game experiences, playing chess variants, writing blogs around game theory, and playing recreational tennis."},
    {"profileId": "maggie-dong", "id": "maggie-dong", "name": "Maggie Dong", "imgurl": "MaggieDong.jpg", "description": "Hi, my name is Maggie, and I’m an incoming 8th grader at Easterbrook Discovery School. I’ve participated in speech and debate since 1st grade, but only started competing seriously in 5th grade. Since then, I've received many awards, mainly in impromptu speaking. I've placed 4th in the Dempsey Cronin Memorial Invitational and 13th in the John Lewis Invitational, and have received numerous finalist and semifinalist awards. In my free time, I enjoy numerous activities, such as hanging out with friends, listening to music, and playing volleyball! I'm super excited to have the opportunity to be a teaching assistant of competitive speech, and I hope to see you there."},
    {"profileId": "mallika-parulekar", "id": "mallika-parulekar", "name": "Mallika Parulekar", "imgurl": "MallikaParulekar.jpg"},
    {"profileId": "martin-cooper", "id": "martin-cooper", "name": "Martin Cooper", "imgurl": "MartinCooper.jpg", "description": "Hello, I am Martin Cooper and I am a senior at Los Altos high school. Since junior high, I have been a straight A student. I enjoy math and solving problems as well as hands on experience such as building a computer from scratch. I got a 5 on the Calculus BC test and have gotten an 800 on the SAT Math II."},
    {"profileId": "matthew-wu", "id": "matthew-wu", "name": "Matthew Wu", "imgurl": "MatthewWu.jpg"},
    {"profileId": "matthew-zhang", "id": "matthew-zhang", "name": "Matthew Zhang", "imgurl": "MatthewZhang.jpg", "description": "Matthew Zhang has been interested in Physics since a very young age. His interest in physics has led him to score a 5 on the AP Physics 1 Exam, become a USAPHO semifinalist, and become an AIME Qualifier. He has been teaching at SVY for 3 years now. He is very excited to interact with and teach the students!"},
    {"profileId": "max-zhang", "id": "max-zhang", "name": "Max Zhang", "imgurl": "MaxZhang.jpg", "description": "Max Zhang is an 7th Grader. He really enjoys playing badminton and is the top in his age group nationally for doubles, winning gold in Nationals for doubles."},
    {"profileId": "michael-hu", "id": "michael-hu", "name": "Michael Hu", "imgurl": "MichaelHu.jpg", "description": "I am a sophomore in Lynbrook High School. I have been playing Bridge for the last 6 years. I am a competitive tournament player. My team won the Grand National Team Flight C Championships, and my Junior team took home the National Youth Swiss Team Championship last summer. I represented US under 16 team in the 17th World Youth Bridge Team Championship this summer, and we won Bronze Medal. I am a volunteer in Silicon Valley Youth Bridge, and I have taught Bridge summer camps for the last three years. In addition, I have also been teaching private bridge lessons at home. Basketball is another one of my hobbies, and I am on the JV Lynbrook Basketball Team. Along with Arthur, my Bridge partner, I am looking forward to sharing the beauty of Bridge with my students."},
    {"profileId": "michael-ma", "id": "michael-ma", "name": "Michael Ma", "imgurl": "MichaelMa.jpg", "description": "Michael grew up in the Silicon Valley and is currently a senior at Lynbrook High School. This will be his tenth session of teaching at SVY. His speech and debate experience involves participating in Miller and Lynbrook’s school team to competing for the Golden State Speech and Debate Academy. Michael has gone to major competitions such as the Berkeley Invitational, Stanford Invitational, and the University of Pacific at Stockton. He has placed 3rd in the Harvey Milk Classic Tournament, and he was an octofinalist in Middle School States. He has deliberated over many urgent topics like solving income inequality by prioritizing the construction and usage of public infrastructure. Outside of speech and debate, Michael enjoys playing volleyball and listening to music. He has also served in Lynbrook's ASB for three years, and is currently one of the student council officers. He is an enthusiastic teacher that looks forward to working with kids and providing the same opportunities that helped him the most."},
    {"profileId": "michael-song", "id": "michael-song", "name": "Michael Song", "imgurl": "MichaelSong.jpg", "description": "Michael is currently a senior at Cupertino High School and has been an avid teacher at Silicon Valley Youth for over three years. A fond computer programmer, Michael loves spending his free time coding and actively participates in online events as well. At school, he earned a 5 on his AP Computer Science test and is proficient in Python, Java, and C++. Additionally, Michael and Austin have taught Python Programming at Silicon Valley for over five semesters and hopes to continue helping students develop their passion for computer science."},
    {"profileId": "michael-tang", "id": "michael-tang", "name": "Michael Tang", "imgurl": "MichaelTang.jpg", "description": "Michael Tang is a sophomore at Lynbrook High School. He has participated in a variety of STEM competitions, achieving AIME qualification with distinction and reaching USACO Silver level. He has experience instructing Computer Science and Math. In his free time, he enjoys playing video games, camping, and spending time with friends."},
    {"profileId": "michael-zheng", "id": "michael-zheng", "name": "Michael Zheng", "imgurl": "MichaelZheng.jpg", "description": "Michael is currently a rising senior at Lynbrook high school. Michael’s favorite subjects are biology and history. He enjoys playing chess, bridge, and sailing in his free time. Michael was introduced to chess at the age of 7, and has thoroughly enjoyed the game. He has reached a chess rating of 1557. Michael also plays bridge, another strategy game with similarities to chess. He has recently won the YNABC title, and continues to enjoy the game. Michael hopes to introduce people to chess and enjoy the game just like he did."},
    {"profileId": "michelle-choi", "id": "michelle-choi", "name": "Michelle Choi", "imgurl": "MichelleChoi.jpg", "description": "Hello! I’m Michelle and I am a sophomore at Cupertino High. I’m informative speech co-captain with Sophie and I compete in Informative Speaking. Although I’ve only been doing Speech for two years, it’s definitely one of my favorite activities. Outside of speech, I read and play the viola."},
    {"profileId": "minglang-du", "id": "minglang-du", "name": "Minglang Du", "imgurl": "MinglangDu.jpg", "description": "Minglang Du is currently a 9th grader at BASIS Independent Silicon Valley in his fourth/fifth year at SVY. He has prior coding and math experience from competitive programming contests (USACO Silver, CALICO, Codeforces). He also has teaching experience as previous TA for Book Club. He loves to code personal projects in his free time. (github.com/minglangdu)"},
    {"profileId": "minh-do", "id": "minh-do", "name": "Minh Do", "imgurl": "MinhDo.jpg", "description": "I'm Minh, and this is my sixth semester as SVY. Serving as an experienced teacher and VP of Media, my students end the semester having experienced at least three Speech and Debate topics, having the capabilities to write a high-school essay, increased people skills, and greater confidence. I always connect with my students on a personal basis in order to tailor learning for them, as there is no one-size-fits-all for learning. In my own learning, I love branching out and exploring a variety of topics. I'm a food blogger, violinist, and serve as the head of the Online Learning Department at BigBang Artwork. I have enjoyed interdisciplinary research in psychology and business, and utilize skills learned through business in my courses. Feel free to shoot me an email with any questions regarding the class."},
    {"profileId": "naomi-wong", "id": "naomi-wong", "name": "Naomi Wong", "imgurl": "NaomiWong.jpg", "description": "Naomi Wong is a junior at The King's Academy who loves science. She is currently taking AP Chemistry and was a TA with SVY last semester. Previously, she has tutored students who struggled with the STEM fields and helped them develop interests in it. Naomi interned at a research company over the summer and is an active volunteer with Group B Strep International. In her free time, you can often find her baking, playing music, or reading. Naomi is so excited to be working with her students this semester!"},
    {"profileId": "neil-weaver", "id": "neil-weaver", "name": "Neil Weaver", "imgurl": "NeilWeaver.jpg", "description": "Neil Weaver is a freshman student at Monta Vista High. He started debating in seventh grade at his middle school’s debate club, staying with it until he went to high school. He has always been excited about the many speaking assignments his class participated in. In his free time, he reads, fences at a local club, argues with his family, and follows the stock market."},
    {"profileId": "oliver-ye", "id": "oliver-ye", "name": "Oliver Ye", "imgurl": "OliverYe.jpg", "description": "Oliver is a Senior at Saratoga High, and has been on the SVY team since the beginning. He’s fascinated with philosophy, and is excited to share his love for metaphysics and epistemology with his students. He is the president of the engineering club, and is a vice president for the science and FBLA clubs as well; in his free time, he enjoys cooking, woodworking, volleyball, and soccer. Though this will be the first semester he is teaching philosophy, he has taught US History and Science Bowl many times in the past, and is very excited to work with his students!"},
    {"profileId": "oliver-zhang", "id": "oliver-zhang", "name": "Oliver Zhang", "imgurl": "OliverZhang.jpg", "description": "Oliver Zhang is a Junior at Proof School. He discovered Machine Learning two and a half years ago and since then has completed two college level courses in ML, a few Kaggle competitions, and has taught two previous classes in Machine Learning. He particularly enjoys the field of Natural Language Processing and tries to stay up to date with the latest research. Besides that, he also enjoys watching other people play video games as well as camping and meeting new people."},
    {"profileId": "paul-zhao", "id": "paul-zhao", "name": "Paul Zhao", "imgurl": "PaulZhao.jpg"},
    {"profileId": "rachel-chan", "id": "rachel-chan", "name": "Rachel Chan", "imgurl": "RachelChan.jpg", "description": "Rachel is currently a senior in Monta Vista and taught Intermediate Java for the past 3 years at SVY. Her interest in coding started in 7th grade and since then she scored a 5 on the AP Computer Science A exam, worked at a tech start-up over summer, and reached USACO Gold. In school, she's an officer in the C++ club and Science National Honor Society, which allows her to explore her interests in all things STEM. Rachel is excited to share her passion for programming this semester!"},
    {"profileId": "ray-zhou", "id": "ray-zhou", "name": "Ray Zhou", "imgurl": "RayZhou.jpg", "description": "Ray Zhou is a Senior at Monta Vista High School. He took AP Computer Science A at Monta Vista High School and AP Computer Science P outside of school—receiving 5s on both tests. He enjoys programming, math, science, and history courses in school, and sports outside of school. He also partakes in the First Robotics Competition and has held the position of operator for the 2018 FRC season on the team Valkyrie Robotics. Ray has co-taught Intermediate Java for two semesters, as well as Intro to Java for one."},
    {"profileId": "raymond-feng", "id": "raymond-feng", "name": "Raymond Feng", "imgurl": "RaymondFeng.jpg", "description": "Raymond is a rising junior at Monta Vista High School. As a USACO Gold qualifier, he understands the struggles of passing USACO Bronze. In addition, Raymond has developed strategies through teaching the course for four semesters. At school, he has founded and led a C++ club for three years and has taught at SVY for six total semesters. He is the Co-president of MV Research Club and the Director of Physics at MV Physics and Engineering Club. Alongside his teaching endeavors, Raymond finds joy in playing the double bass, designing kusudama, competition physics, photographing airplanes, and learning worldwide languages."},
    {"profileId": "redger-xu", "id": "redger-xu", "name": "Redger Xu", "imgurl": "RedgerXu.jpg", "description": "Redger Xu is currently a senior at Stratford Prepatory starting his third year at SVY. He has been programming for several years, with experience in a variety of programming languages as well as scoring a 5 on the AP CS A exam. He is also the president of the Hackathon club and has participated in numerous programming competitions. Redger enjoys playing tennis, working on coding projects, and learning new pieces of math."},
    {"profileId": "rocky-yang", "id": "rocky-yang", "name": "Rocky Yang", "imgurl": "RockyYang.jpg", "description": "Rocky Yang is one of the top badminton players in his age group, consistently achieving good results in national level tournaments."},
    {"profileId": "royce-ren", "id": "royce-ren", "name": "Royce Ren", "imgurl": "RoyceRen.jpg", "description": "Hi! My name is Royce Ren and I am a senior at Cupertino High School. I have been doing public speaking ever since the start of middle school. I’ve been in almost a dozen plays, given countless numbers of speeches in front of a live audience, and have even given tours to the public at an internship at the Computer History Museum. Recently, I have joined the competitive speech and debate scene, moving as far forward as semi-finals at Santa Clara University in Original Oratory. In the debate context, I have gone to a state-level qualifier tournament and have ranked top 500 across the nation. I also have traveled across the nation to attend top speech and debate camps in multiple states, and I look forward teaching at SVY!"},
    {"profileId": "rufan-yin", "id": "rufan-yin", "name": "Rufan Yin", "imgurl": "RufanYin.jpg", "description": "Rufan is a junior at Stratford Preparatory HS, and has been coding since 4th grade. He has taken CS A and knows Java, Python, PyTorch, NodeJs, and full stack development. In his free time, he likes to work on and fly his RC plane."},
    {"profileId": "sam-yang", "id": "sam-yang", "name": "Sam Yang", "imgurl": "SamYang.jpg", "description": "Sam Yang is a senior at Monta Vista High School. He is an avid web developer and programmer, and is fluent in HTML, CSS, Javascript and jQuery, as well as had experience with Firebase, Node.js, PHP, React, Java and Python. He is a current co-president of Silicon Valley Youth, and created the Silicon Valley Youth website. He has taught one semester of Intro to Web Design, and one semester of Advanced Web Design. He developed websites for organizations like EngAcademy, InstaTutors, Silicon Valley Forensics, DeltaHacks Institute, HSHacks and Matadorhacks. He has also taught web design workshops at various hackathons, like SRCCode, Digitize, HSHacks and more. In his free time, he enjoys making music and playing basketball. He is very enthusiastic about Web Design, and looks forward to teaching the Intro to Web Design course!"},
    {"profileId": "samika-swamy", "id": "samika-swamy", "name": "Samika Swamy", "imgurl": "SamikaSwamy.jpg", "description": "Samika is a senior at Monta Vista High School. She is passionate about science, technology and related interdisciplinary fields. She has channeled her interests especially in the areas of environmental engineering and neuroscience, which has led to her winning several regional, state, and national awards for her research & engineering projects. She loves to give back to the community through a plethora of different outlets including her contributions to guidance and mentorship for middle school students, her leadership in non-profit organizations in the biotechnology field, as well as volunteering at local hospitals. Outside of STEM, Samika enjoys performing Indian classical dance, doing calligraphy, and hiking with her family and friends."},
    {"profileId": "samuel-chen", "id": "samuel-chen", "name": "Samuel Chen", "imgurl": "SamuelChen.jpg", "description": "Samuel Chen is currently a junior at Gunn High School and has been teaching Science Bowl for a year. He participates in Science Olympiad at his school, where he has achieved two medals so far. Outside of his interest in STEM subjects, he enjoys playing his instrument, running, and games."},
    {"profileId": "samuel-ma", "id": "samuel-ma", "name": "Samuel Ma", "imgurl": "SamuelMa.jpg", "description": "Hi everyone! I’m Samuel Ma, a rising junior on the Bellarmine Speech and Debate Team. I’ve competed in speech and debate for 6 years now. I primarily compete in Extemp and Impromptu at the high school level. Amongst California high schoolers, I’m currently ranked 2nd in Impromptu and was finalist in National Extemp at the 2025 California High School State Championship Tournament. I was also a finalist at the Stanford 2024 Invitational in both Varsity Extemp and Impromptu. I look forward to sharing my knowledge and experience with all of you! Besides that, I enjoy learning about economics and politics in my free time."},
    {"profileId": "samuel-shen", "id": "samuel-shen", "name": "Samuel Shen", "imgurl": "SamuelShen.jpg", "description": "My name is Samuel and this will be my first time teaching at SVY. I will be co-teaching World History for the 2019 Spring semester. I love history, as it is really just a series of tales about our forefathers. I am a sophomore at Fremont High School, and I am also taking AP World History, so I have the privilege of teaching the content as I learn it. I am excited, and I hope to gain some experience working with my co-teacher and the students that I teach!"},
    {"profileId": "samuel-yang", "id": "samuel-yang", "name": "Samuel Yang", "imgurl": "SamuelYang.jpg"},
    {"profileId": "saria-lum", "id": "saria-lum", "name": "Saria Lum", "imgurl": "SariaLum.jpg", "description": "Saria Lum is a current 10th grader at the Harker School. Her love for research started in 8th grade in her school's Science Research Project (SRP) program, where she first learned to conduct science-fair research. Eventually researching sustainable ways to create seaweed biofabric, she has won multiple awards in both local and state science fairs, as well as an invitation to ThermoFisher Scientific's Junior Innovators Challenge, where she won top 300. In her free time, Saria enjoys dancing ballet, debate, and science research. She hopes to become a dermatologist in the future, with the goal of helping others feel comfortable in their own skin."},
    {"profileId": "sarialum", "id": "sarialum", "name": "SariaLum", "imgurl": "SariaLum.jpg"},
    {"profileId": "seabert-mao", "id": "seabert-mao", "name": "Seabert Mao", "imgurl": "SeabertMao.jpg", "description": "Seabert is a junior at Saratoga High with a strong passion for mathematics. He has won numerous awards in math competitions, including being an AIME qualifier since 5th grade, achieving a perfect score on the AMC10 Distinguished Honor Roll, and qualifying for the USAJMO. During middle school, he was the MathCounts State Champion in California and a finalist in MathCounts National Competition, where he won 6th place nationally."},
    {"profileId": "sean-wu", "id": "sean-wu", "name": "Sean Wu", "imgurl": "SeanWu.jpg", "description": "Sean Wu is a Senior at Henry M. Gunn High School with a lifelong passion for history. He enjoys watching WWI and WWII documentaries and visiting local history museums during his travels to explore life in the past. He has written WWII-related blogs for the non-profit Pacific Atrocities Education and researched the economic and political developments of historical events. He also enjoys playing chess, music, following basketball, and major sporting events like the Olympics. His aim is to inspire more people and give history more attention through his classes."},
    {"profileId": "sean-yang", "id": "sean-yang", "name": "Sean Yang", "imgurl": "SeanYang.jpg", "description": "Sean Yang is a senior at Monta Vista High School. In the past few years, he has solidified his passion for STEM through various competitions and camps. His interest in computer science has led him to qualify for Gold in USACO and lead a coding organization called TeamsCode; his interest in mathematics has led him to qualify for the American Invitational Mathematics Exam (AIME) twice; and his aptitude for physics has led him to receive a 5 on the AP Physics 1 Exam, 800 on the SAT Physics, and qualify for USAPhO semifinalists. He has taught at SVY for more than 5 semesters and has helped students develop their passion for mathematics and enhance problem solving skills in his AMC 8 and Discrete Math classes. This year, he looks forward to teaching discrete math and further spreading his passion for STEM to his students!"},
    {"profileId": "sharon-zhu", "id": "sharon-zhu", "name": "Sharon Zhu", "imgurl": "SharonZhu.jpg", "description": "Hi! My name is Sharon Zhu, and I am a senior at Lynbrook High School. I've been teaching the class for the last few years, and look forward to another great semester! I've scored a 5 on the AP Biology exam, was a semifinalist for the USA Biology Olympiad, and was a National Science Bowl champion last summer. I have been a bio nerd since elementary school, and I hope to instill the same curiosity for students this semester!"},
    {"profileId": "shawn-huang", "id": "shawn-huang", "name": "Shawn Huang", "imgurl": "ShawnHuang.jpg", "description": "Hello, I am Shawn Huang, a senior at Los Altos High School and I will be your iOS App Development teacher. I have been an avid programmer for the past 6 years, with extensive experience in both Java and Swift as well as some experience in Python, HTML, and Javascript. I have also taught at Streetcode Academy, an organization which helps people of underrepresented groups in the tech industry learn how to code, for a few months. I am well versed in competition math, having qualified for the AIME through the AMC 10 and 12 the past 3 years. My other hobbies include playing tennis and reading."},
    {"profileId": "shreya-kashyap", "id": "shreya-kashyap", "name": "Shreya Kashyap", "imgurl": "ShreyaKashyap.jpg", "description": "Hi! My name is Shreya Kashyap, and I’m a senior at Monta Vista High School. I am passionate about life sciences and biology, and I’m interested in pursuing a career in medicine. Throughout high school, I have taken Biology, Psychology, and AP Biology at school, tutored students in chemistry and biology, and taken part in cell biology research. Outside of school, I love to dance, read fiction novels, sketch with pen, and bake with my sister."},
    {"profileId": "shreyas-rana", "id": "shreyas-rana", "name": "Shreyas Rana", "imgurl": "ShreyasRana.jpg", "description": "Shreyas is a Junior at Saratoga High School and will be the teacher for Intro to Machine Learning. This will be his fourth term teaching at Silicon Valley Youth. He is fluent in Java, Python, Flutter/Dart, and Javascript. He has taught elementary schoolers and Boys Scouts robotics and has traveled internationally for volunteering. Shreyas has participated in several competitions such as reaching USACO Gold and the FIRST Robotics Challenge - reaching the semifinals at the World tournament in Houston. He is a co-president of his app-dev club at school, and is the Software Lead at his FRC Robotics Club. In his free time, he likes to make art, work on research projects, and play Call of Duty. Shreyas is very excited to be teaching Machine Learning this year."},
    {"profileId": "siddhanth-venkatesan", "id": "siddhanth-venkatesan", "name": "Siddhanth Venkatesan", "imgurl": "SiddhanthVenkatesan.jpg", "description": "Hi! My name is Sid and I’m a high school sophomore at Leigh high school. This is my first semester teaching at SVY and I am incredibly excited to begin my teaching journey. I am very interested in the intersection of biology and chemistry, and have taken a chemistry honors course in my school. Looking forward to seeing you in class!"},
    {"profileId": "skyler-mao", "id": "skyler-mao", "name": "Skyler Mao", "imgurl": "SkylerMao.jpg", "description": "Hi, I'm Skyler, a senior at Saratoga High School. Throughout the years, I've participated in a lot of math competitions, qualifying for USA(J)MO 3 times during high school. I've previously taught debate at SVY for 4 semesters, but this year I'm looking forward to teaching AMC 10. I hope to see you in class!"},
    {"profileId": "sonia-swamy", "id": "sonia-swamy", "name": "Sonia Swamy", "imgurl": "SoniaSwamy.jpg", "description": "Sonia is a rising sophomore at Monta Vista High School. Passionate about STEM, she has solidified her interests in the fields of biomedicine and environmental science, through conducting various research projects, ultimately culminating in several prestigious awards, such as 1st place at Synopsys Science Fair, 4th place at California State Science Fair, and Broadcom MASTERS National Top 300. Additionally, she has excelled in NGN Hacks and the Conrad Innovation Challenge, proposing a successful clean energy initiative along with her team. In her spare time, Sonia can be found practicing Bharatanatyam, a unique form of Indian classical dance, which she enjoys for its intertwinement of grace, technique, and expression. She is very excited to share her knowledge and zeal for this fascinating subject with her students!"},
    {"profileId": "sophia-zhu", "id": "sophia-zhu", "name": "Sophia Zhu", "imgurl": "SophiaZhu.jpg", "description": "Sophia Zhu is a 9th grader at The Harker School. After taking Advanced Programming over the 2021 summer, she then tested into AP Computer Science A with Data Structures, which she is currently taking. She has been coding in Java for the last 2.5 years and is a USACO Silver competitor. Other than programming, Sophia also plays club volleyball and participates in other STEM-related activities, such as robotics. As seen from her Spotify and Netflix history, Sophia enjoys watching anime and listening to Kpop in her free time. With all that said, Sophia cannot wait to teach Intro to Java this upcoming semester!"},
    {"profileId": "sophie-yang", "id": "sophie-yang", "name": "Sophie Yang", "imgurl": "SophieYang.jpg", "description": "Heyo! My name is Sophie, and I am a sophomore at Cupertino High. I’m informative speech co-captain with Michelle and I’ve competed in both Informative Speech and Public Forum Debate. I’ve placed 2nd at SCU and CFL 2 as well as 3rd at CFL novice and Stephan Stewart. Outside of speech, I perform for my school's drama department."},
    {"profileId": "spencer-he", "id": "spencer-he", "name": "Spencer He", "imgurl": "SpencerHe.jpg", "description": "Spencer is a senior at Valley Christian High School and has been studying business since seventh grade. He has many achievements in DECA and other business/entrepreneurship competitions, such as Diamond Challenge. At school he helps lead his DECA chapter and developed a startup in an incubator program. Apart from business, Spencer plays trumpet and badminton at school. This is his fifth semester at SVY and looks forward to meeting you!"},
    {"profileId": "stanley-wan", "id": "stanley-wan", "name": "Stanley Wan", "imgurl": "StanleyWan.jpg", "description": "My name is Stanley and I am a sophomore at Woodside Priory school. I have been doing public forum debate for a year, and competed in 3 tournaments since the beginning of this year. I also started a debate club at school with my debate partner. I hope to be able to help others improve on their public speaking skills."},
    {"profileId": "stefan-meier", "id": "stefan-meier", "name": "Stefan Meier", "imgurl": "StefanMeier.jpg", "description": "My name is Stefan Meier, and I am a junior at Saratoga High School. I really enjoy playing tennis, and have been playing since I was 7 years old. Two years ago year, I made my high school varsity tennis team, and played as high as Singles #2 . I have volunteered at my coach’s clinic, where I taught younger kids who were mostly beginners. In addition, I have been playing competitive tennis since a very young age, and won many tournaments, too. I have a strong passion for the sport, and I would love to spread it to others."},
    {"profileId": "stephanie-lee", "id": "stephanie-lee", "name": "Stephanie Lee", "imgurl": "StephanieLee.jpg"},
    {"profileId": "steven-long", "id": "steven-long", "name": "Steven Long", "imgurl": "StevenLong.jpg", "description": "My name is Steven and I am currently a senior at Monta Vista High School. I enjoy a variety of engineering and science related subjects, and I participate in my school's robotics team. At SVY, I have previously taught and served as a TA for Java and web development classes. In my free time, I enjoy sleeping, watching Netflix, and playing the bassoon. I am beyond excited to be your teacher!"},
    {"profileId": "sudithi-manthati", "id": "sudithi-manthati", "name": "Sudithi Manthati", "imgurl": "SudithiManthati.jpg", "description": "Sudithi Manthati is a sophomore at Fremont High. Her interests include science, violin, and cross-country. Recently taking part in the NGCC2020 competition and CONRAD Challenge 2021, she and her team won awards for their sustainable, zero-waste energy solution. In her free time, she enjoys volunteering for the Humane Society Silicon Valley and the City of Sunnyvale. She has actively raised money for the Humane Society, World Wildlife Fund, St. Jude’s Children’s Hospital, and Cancer Care. Sudithi especially enjoys biology and chemistry and looks forward to working with her students."},
    {"profileId": "susan-liu", "id": "susan-liu", "name": "Susan Liu", "imgurl": "SusanLiu.jpg", "description": "Hi! My name is Susan and I'm a sophomore at Lynbrook. I've always loved reading and discussing stories. I believe books can bring people together, spark imagination, and help us see the world through different perspectives. Outside reading and writing, I enjoy expressing myself by playing tennis, creating art, and performing in drama. I can't wait to learn and grow alongside my students this semester!"},
    {"profileId": "taimin-lio", "id": "taimin-lio", "name": "Taimin Lio", "imgurl": "TaiminLio.jpg"},
    {"profileId": "tanay-parikh", "id": "tanay-parikh", "name": "Tanay Parikh", "imgurl": "TanayParikh.jpg", "description": "Tanay Parikh is currently a sophomore at Monta Vista High School. He is interested in Machine Learning and is passionate about Java, Swift and Robotics. Further, Tanay has worked on Arduino based projects as well as numerous automation projects with Python. Previously, he has been a teaching assistant for Python at SVY. Tanay also enjoys running in Cross Country and Track & Field, and is on an FRC Robotics Team."},
    {"profileId": "thomas-wu", "id": "thomas-wu", "name": "Thomas Wu", "imgurl": "ThomasWu.jpg", "description": "Thomas Wu is an 12th grader at Lynbrook high school and has been teaching Science Bowl for 2 years. He participates in Science Bowl as well as Science Olympiad and Ocean Science Bowl. Thomas is excited to teach Science Bowl at SVY again and to meet new students."},
    {"profileId": "tim-jing", "id": "tim-jing", "name": "Tim Jing", "imgurl": "TimJing.jpg", "description": "Tim is a 12th-grade student at Lynbrook High School. He has co-taught Science Bowl for nine semesters. In his free time, Tim loves competing on the Lynbrook Science Olympiad team, reading exciting new biology articles, playing volleyball, and eating good food. Tim enjoys teaching, communicating, and is excited to work with his students!"},
    {"profileId": "timothy-leung", "id": "timothy-leung", "name": "Timothy Leung", "imgurl": "TimothyLeung.jpg", "description": "Hey guys, my name is Timothy, and I am a senior at Saratoga High School. I began participating in various public speaking competitions in 1st grade, but only formally joined Speech and Debate in 7th grade. Since then, I have garnered achievements such being the District Champion, a finalist at the Tournament of Champions, a semifinalist at the prestigious National Speech and Debate Tournament (where the picture is from), and the California State Champion! I love participating in Speech and Debate and I love teaching it even more, so I am very excited to meet you all!"},
    {"profileId": "tony-jiang", "id": "tony-jiang", "name": "Tony Jiang", "imgurl": "TonyJiang.jpg", "description": "Greetings Everyone! My name is Tony Jiang, a senior at Saratoga High School, and I have been teaching Public Speaking at SVY for 4 years and have been on SVY's teacher team for 6 semesters. I have read many books on public speaking theory as well as have experience public speaking as a Saratoga City Council intern and speaking at many other events. I am passionate about teaching students how important public speaking is and improving their speaking skills."},
    {"profileId": "tony-liao", "id": "tony-liao", "name": "Tony Liao", "imgurl": "TonyLiao.jpg"},
    {"profileId": "tony-zhou", "id": "tony-zhou", "name": "Tony Zhou", "imgurl": "TonyZhou.jpg", "description": "Hi! My name is Tony Zhou and I am a senior at Los Gatos High School. I have been coding since very early in elementary school, and I am thrilled to be able to share my knowledge and passion for computer science with all of you. I have taught at SVY for a while now and I hope to have another memorable and great semester. Outside of computer science, I enjoy playing soccer, hanging out with friends, and playing music. I hope we can have a great semester together."},
    {"profileId": "trevor-leung", "id": "trevor-leung", "name": "Trevor Leung", "imgurl": "TrevorLeung.jpg", "description": "Trevor is currently a sophomore at Saratoga High School, and has been on a robotics team for 2 years. He is currently on Saratoga High's veteran FTC team and has 3 years of Autodesk Experience. He also knows a bit of Solidworks. Outside of robotics and CAD, he is in the orchestra and science olympiad team."},
    {"profileId": "trinity-gao", "id": "trinity-gao", "name": "Trinity Gao", "imgurl": "TrinityGao.jpg"},
    {"profileId": "tristan-cooper", "id": "tristan-cooper", "name": "Tristan Cooper", "imgurl": "TristanCooper.jpg", "description": "Hello, I am Tristan Cooper, an 12th grade student at Proof School, a math focused private school in San Francisco. I will be your teacher. I have gotten a 5 on the AP Calculus BC test, and I got an 800 on the SAT Math II test. I have qualified for the AIME three times. I enjoy solving math problems in my spare time, and I am currently studying Chinese. I also enjoy reading fantasy books."},
    {"profileId": "victor-shen", "id": "victor-shen", "name": "Victor Shen", "imgurl": "VictorShen.jpg", "description": "Victor Shen is a senior at Lynbrook High School. He has extensive experience in Java programming, having achieved USACO Platinum and a 5 on the AP Computer Science exam. Although he focuses primarily on Java, Victor has utilized Python, C++, and C# in fields such as data analysis, robotics, and game development. During the past three SVY semesters, he co-taught Intermediate Java and USACO Bronze classes. Outside of school, he competes on the Varsity badminton team and plays clarinet in the California Philharmonic Youth Orchestra."},
    {"profileId": "viola-zhao", "id": "viola-zhao", "name": "Viola Zhao", "imgurl": "ViolaZhao.jpg", "description": "Viola Zhao is a high school senior at Los Gatos High School. She is the co-founder of Coding in the Community and an alumni of the Girls Who Code Summer Immersion Program at the IBM Bay Area location. Along with three other girls, she has developed an app called NutriScan, which was featured on the Girls Who Code front page here. Viola has had over four years of programming experience and has learned various languages over the years, such as Swift, Python, Java, HTML & CSS, and C++. Aside from her experience in programming, she also has teaching experience working with special needs children and teaching design media arts to Chinese students."},
    {"profileId": "wendy-liu", "id": "wendy-liu", "name": "Wendy Liu", "imgurl": "WendyLiu.jpg", "description": "Wendy Liu has studied music since childhood, with experience in instrumental (violin, piano) and vocal music. Awards include American Protégé, Golden Classical Music Awards, Grand Prize Virtuoso. Wendy has previously been invited to the California Choral Directors Association's Regional and All-State Honor Choirs, and currently performs in the chamber ensemble Capriccio as an Alto and section leader. As a multidisciplinary artist, Wendy is also interested in dance and theater, and is a California Arts Scholar."},
    {"profileId": "william-zhuang", "id": "william-zhuang", "name": "William Zhuang", "imgurl": "WilliamZhuang.jpg", "description": "William Zhuang is a junior at Basis Independent Silicon Valley. Physics is one of the most tangible sciences, as it illustrates the fundamental principles of the world around us. He is eager to apply his experience in physics to help others understand concepts as well as gain knowledge and practical experience."},
    {"profileId": "winnie-zhao", "id": "winnie-zhao", "name": "Winnie Zhao", "imgurl": "WinnieZhao.jpg"},
    {"profileId": "yang-gao", "id": "yang-gao", "name": "Yang Gao", "imgurl": "YangGao.jpg", "description": "Currently a sophomore at Leigh High School, Yang got first place individual debate and first place team debate at World Scholars Cup and competes at Varsity level internationally. He has a few years of experience in competing in speech and debate events. Yang has 2 years of teaching experience and is eager to help people become better communicators."},
    {"profileId": "yash-ranjith", "id": "yash-ranjith", "name": "Yash Ranjith", "imgurl": "YashRanjith.jpg", "description": "Yash Ranjith is a senior at Westmont High School. He loves to code and is passionate about climate sciences and sustainability. His research focuses on using machine learning to address environmental issues like pollution, and wildfire smoke. Yash is a USACO Finalist and has been teaching at SVY for the past 3 years. In his spare time, Yash is a foil fencer and enjoys bouldering."},
    {"profileId": "yashnil-mohanty", "id": "yashnil-mohanty", "name": "Yashnil Mohanty", "imgurl": "YashnilMohanty.jpg", "description": "Yashnil Mohanty is a senior at Westmont High School. He loves to code and is passionate about teaching, leadership, and working with others. His interests lie in applying machine learning to real-world challenges, especially in environmental science and sustainability. Yashnil is a USACO Gold competitor and has been teaching Java at SVY for two years. In his spare time, he enjoys running, skiing, and watching or playing sports."},
    {"profileId": "yaswanth-jampani", "id": "yaswanth-jampani", "name": "Yaswanth Jampani", "imgurl": "YaswanthJampani.jpg"},
    {"profileId": "yilang-han", "id": "yilang-han", "name": "Yilang Han", "imgurl": "YilangHan.jpg", "description": "Yilang Han is an 8th grader at Georgina P. Blach Junior High School and is starting his first semester at SVY. He started his coding journey in the same class he is teaching, and is now proficient in both Python and C++. As a hobbyist coding/computer enthusiast, he enjoys writing his own apps, games, and operating systems and messing with old hardware. Outside of coding, he plays piano and table tennis."},
    {"profileId": "yitao-li", "id": "yitao-li", "name": "Yitao Li", "imgurl": "YitaoLi.jpg", "description": "Yitao Li is a junior at the King's Academy. She has been taking Chemistry Honors and AP Chemistry classes for the past 2 years, and she finds the subject to be a stimulating challenge. She hopes to inspire her students to pursue their passion for science through the exploration of the fundamental pillars of chemistry. In her free time, she enjoys dabbling in theater and music, as well as exploring her interests in literature and the humanities."},
    {"profileId": "yutong-qiu", "id": "yutong-qiu", "name": "Yutong Qiu", "imgurl": "YutongQiu.jpg", "description": "Hey! I'm Yutong and I am a sophomore at Lynbrook High School. I have experience in math competitions such as the AMCs, AIME, BMT, and SMT. I also compete in computer science and physics competitions. Beyond this, I enjoy playing violin and piano, playing badminton and tennis, drawing, and listening to music."},
    {"profileId": "zachary-george", "id": "zachary-george", "name": "Zachary George", "imgurl": "ZacharyGeorge.jpg", "description": "Zachary is a Senior at Lynbrook High School. Throughout high school beginning with freshman year, he took Computer Programming Java. In addition to Java, Zachary is fluent in HTML, python, and Java. After Computer Programming Java, Zachary decided to take AP Computer Science his junior year. Additionally, Zachary is interested in math, earning a 5 on AP Calculus BC. Outside of school Zachary plays guitar and is a TA for his local Sunday School. When he's not coding, you can find him binging Netflix or watching YouTube."},
    {"profileId": "zachary-wang", "id": "zachary-wang", "name": "Zachary Wang", "imgurl": "ZacharyWang.jpg", "description": "Hello! I am a junior at Homestead High School. I’m currently taking AP Physics C, and I received a 5 on the AP Physics 1 exam. Last semester, I was the teacher for Physics. Outside of school, I enjoy playing badminton and am an avid member of boy scouts."}
]

function normalizeProfileName(name) {
    return String(name || "").replace(/\s+/g, " ").trim().toLowerCase();
}

function profileSlugFromName(name) {
    return normalizeProfileName(name).replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}

var SVYProfiles = window.SVYProfiles || {
    profilesById: {},
    profilesByName: {},
    normalizeName: normalizeProfileName,
    profileIdFromName: profileSlugFromName,
    normalizeProfile: function(profile) {
        var next = Object.assign({}, profile);
        next.profileId = next.profileId || next.id || this.profileIdFromName(next.name);
        next.id = next.id || next.profileId;
        return next;
    },
    register: function(profile) {
        if (!profile || !profile.id || !profile.name) {
            throw new Error("SVY profile requires unique id and name");
        }
        profile = this.normalizeProfile(profile);
        if (this.profilesById[profile.profileId]) {
            throw new Error("Duplicate SVY profile id: " + profile.profileId);
        }
        this.profilesById[profile.profileId] = Object.assign({}, profile);
        var key = this.normalizeName(profile.name);
        if (this.profilesByName[key] && this.profilesByName[key].profileId !== profile.profileId) {
            this.profilesByName[key] = null;
        } else {
            this.profilesByName[key] = this.profilesById[profile.profileId];
        }
        return this.profilesById[profile.profileId];
    },
    registerLegacy: function(profile) {
        if (!profile || !profile.name) {
            return null;
        }
        profile = this.normalizeProfile(profile);
        var key = this.normalizeName(profile.name);
        if (this.profilesById[profile.profileId] && this.normalizeName(this.profilesById[profile.profileId].name) !== this.normalizeName(profile.name)) {
            throw new Error("Duplicate SVY profile id: " + profile.profileId);
        }
        var existingByName = this.profilesByName[key];
        if (existingByName && existingByName.profileId !== profile.profileId) {
            profile.profileId = existingByName.profileId;
            profile.id = existingByName.id || existingByName.profileId;
        }
        this.profilesById[profile.profileId] = Object.assign({}, this.profilesById[profile.profileId] || {}, profile);
        this.profilesByName[key] = this.profilesById[profile.profileId];
        return this.profilesByName[key];
    },
    registerMany: function(profiles) {
        if (!profiles) {
            return;
        }
        for (var i = 0; i < profiles.length; i++) {
            this.registerLegacy(profiles[i]);
        }
    },
    get: function(profileRef) {
        if (this.profilesById[profileRef]) {
            return this.profilesById[profileRef];
        }
        var profile = this.profilesByName[this.normalizeName(profileRef)];
        if (profile === null) {
            throw new Error("Ambiguous SVY profile name, use profile id: " + profileRef);
        }
        return profile || { id: this.profileIdFromName(profileRef), profileId: this.profileIdFromName(profileRef), name: profileRef || "", imgurl: "noimage.png" };
    },
    imagePath: function(profileRef, options) {
        var profile = this.get(profileRef);
        var basePath = options && options.basePath ? options.basePath : "images/teamphoto/";
        return basePath + (profile.imgurl || "noimage.png");
    },
    profileUrl: function(profileRef) {
        var profile = this.get(profileRef);
        return "/profile.html?id=" + encodeURIComponent(profile.profileId || profile.id || profileRef || profile.name);
    },
    description: function(profileRef, fallback) {
        var profile = this.get(profileRef);
        return profile.description || fallback || "";
    }
};

for (var profileIndex = 0; profileIndex < profiles.length; profileIndex++) {
    SVYProfiles.register(profiles[profileIndex]);
}

function findKnownSVYProfile(profileRef) {
    if (!profileRef) {
        return null;
    }
    if (SVYProfiles.profilesById && SVYProfiles.profilesById[profileRef]) {
        return SVYProfiles.profilesById[profileRef];
    }
    var key = SVYProfiles.normalizeName(profileRef);
    return SVYProfiles.profilesByName ? SVYProfiles.profilesByName[key] : null;
}

function applySVYProfileDescriptions(profiles) {
    if (!profiles) {
        return;
    }
    for (var i = 0; i < profiles.length; i++) {
        if (!profiles[i].description) {
            continue;
        }
        var localProfile = findKnownSVYProfile(profiles[i].profileId) || findKnownSVYProfile(profiles[i].id) || findKnownSVYProfile(profiles[i].name);
        if (!localProfile || !localProfile.name) {
            continue;
        }
        SVYProfiles.registerLegacy({
            profileId: localProfile.profileId || localProfile.id,
            id: localProfile.id || localProfile.profileId,
            name: localProfile.name,
            imgurl: localProfile.imgurl,
            description: profiles[i].description
        });
    }
}

function loadDynamicSVYProfileDescriptions() {
    var config = window.SVY_CONFIG || {};
    var backendBaseUrl = config.backendBaseUrl || "https://siliconvalleyyouth.herokuapp.com";
    if (!window.fetch) {
        return;
    }
    fetch(backendBaseUrl + "/api/profile-descriptions")
        .then(function(response) { return response.ok ? response.json() : { profiles: [] }; })
        .then(function(payload) { applySVYProfileDescriptions(payload.profiles || []); })
        .catch(function() {});
}

window.SVYProfiles = SVYProfiles;
loadDynamicSVYProfileDescriptions();
